(function(){var items=[{"id":"l_06_01","q":"투안 씨는 어는 나라 사람입니까?","audio":"안녕하세요. 저는 투안입니다. 베트남 사람입니다. 만나서 반갑습니다.","a":["한국 사람입니다","태국 사람입니다","베트남 사람입니다","파키스탄 사람입니다"],"c":"베트남 사람입니다","ex":"Dalam audio, Tuan secara jelas menyebutkan bahwa dia adalah orang Vietnam (베트남 사람).","romaji":"Tuan ssineun eoneu nara saram-imnikka?","ch":6},{"id":"l_06_02","q":"이 사람은 직업이 무엇입니까?","audio":"민수 씨는 학생입니까? 아니요, 저는 회사원입니다. 투안 씨도 회사원입니까?","a":["학생입니다","요리사입니다","의사입니다","회사원입니다"],"c":"회사원입니다","ex":"Pembicara (Minsu) menyatakan bahwa dia bukan pelajar, melainkan pegawai perusahaan (회사원).","romaji":"I sarameun jigyeobi mueosimnikka?","ch":6},{"id":"l_06_03","q":"말하는 사람은 누구입니까?","audio":"안녕하세요. 저는 이영진입니다. 인도네시아 사람입니다. 처음 뽑겠습니다.","a":["이영진 씨입니다","이민수 씨입니다","투안 씨입니다","리한 씨입니다"],"c":"이영진 씨입니다","ex":"Audio berisi pengenalan diri oleh Lee Yeong-jin.","romaji":"Malhaneun sarameun nugu-imnikka?","ch":6},{"id":"l_06_04","q":"대화 내용과 다른 것을 고르십시오.","audio":"가: 안녕하세요. 저는 바루입니다. 나: 반갑습니다, 바루 씨. 저는 준구입니다. 바루 씨는 어는 나라 사람입니까? 가: 저는 파키스탄 사람입니다. 준구 씨는 학생입니까? 나: 아니요, 저는 공무원입니다. 바루 씨는 직업이 무엇입니까? 가: 저는 기술자입니다.","a":["바루 씨는 파키스탄 사람입니다","준구 씨는 학생입니다","바루 씨는 기술자입니다","준구 씨는 공무원입니다"],"c":"준구 씨는 학생입니다","ex":"준구 (Jungu) mengatakan \"아니요, 저는 공무원입니다\" yang berarti dia adalah PNS, bukan pelajar.","romaji":"Daehwa naeyong-gwa dareun geoseul goreusipsio.","ch":6},{"id":"l_06_05","q":"들은 내용과 같은 직업을 고르십시오.","audio":"안녕하세요. 제 이름은 리한입니다. 저는 파키스탄에서 왔습니다. 제 직업은 목수입니다. 오늘은 처음 회사에 왔습니다. 만나서 정말 반갑습니다. 우리 같이 열심히 일합시다. 감사합니다.","a":["요리사","간호사","목수","농부"],"c":"목수","ex":"Rihan menyebutkan bahwa pekerjaannya adalah tukang kayu (목수).","romaji":"Deureun naeyong-gwa gateun jigeobeul goreusipsio.","ch":6},{"id":"l_07_01","q":"여기가 어디입니까?","audio":"여기가 사무실입니까? 네, 사무실입니다. 화장실은 어디입니까? 저기입니다.","a":["식당입니다","화장실입니다","사무실입니다","기숙사입니다"],"c":"사무실입니다","ex":"Pembicara pertama bertanya apakah itu kantor (사무실) dan dijawab \"Ya\".","romaji":"Yeogiga eodi-imnikka?","ch":7},{"id":"l_07_02","q":"이것은 무엇입니까?","audio":"투안 씨, 이게 뭐예요? 아, 이건 제 가족사진이에요. 그리고 이건 기숙사 열쇠예요.","a":["여권입니다","지갑입니다","가족사진입니다","가방입니다"],"c":"가족사진입니다","ex":"Benda yang ditanyakan diidentifikasi sebagai foto keluarga (가족사진).","romaji":"Igeoseun mueosimnikka?","ch":7},{"id":"l_07_03","q":"화장실이 어디에 있습니까?","audio":"실예합니다. 식당이 어디입니까? 식당은 저기입니다. 그럼 화장실은 어디입니까? 화장실은 식당 옆에 있습니다.","a":["식당 앞","식당 옆","사무실 앞","기숙사 옆"],"c":"식당 옆","ex":"Lokasi kamar mandi ada di sebelah restoran (식당 옆).","romaji":"Hwajangsiri eodie isseumnikka?","ch":7},{"id":"l_07_04","q":"들은 내용과 관계없는 물건을 고르십시오.","audio":"제 가방 안에 물건이 많아요. 여권하고 지갑이 있어요. 그리고 추워서 이불도 가져왔요. 아, 기숙사 열쇠도 가방에 있어요. 그런데 우산은 없어요.","a":["여권","지갑","이불","우산"],"c":"우산","ex":"Pembicara menyebutkan paspor, dompet, selimut, dan kunci ada di tas, tetapi payung (우산) tidak ada.","romaji":"Deureun naeyong-gwa gwangye-eomneun mulgeoneul goreusipsio.","ch":7},{"id":"l_07_05","q":"여자는 지금 어디에 가고 싶어합니까?","audio":"가: 여기가 시장입니까? 나: 아니요, 마트입니다. 시장은 저기 머리 있어요. 가: 그래요? 저는 오늘 과일을 사고 싶어요. 그럼 마트에서 과일을 팔아요? 나: 네, 마트에도 과일이 많아요. 가: 그럼 여기서 쇼핑할게요. 감사합니다.","a":["시장","마트","회사","미용실"],"c":"마트","ex":"Wanita tersebut memutuskan untuk belanja di mart (마트) setelah mengetahui mart juga menjual buah.","romaji":"Yeojaneun jigeum eodie gago sipeohamnikka?","ch":7},{"id":"l_08_01","q":"투안 씨는 지금 무엇을 합니까?","audio":"투안 씨, 지금 뭐 해요? 저는 지금 싸어요. 그리고 요리해요. 수루 씨는 뭐 해요?","a":["자요","싸어요","일해요","운동해요"],"c":"싸어요","ex":"Tuan menjawab bahwa dia sedang mandi/mencuci (싸어요).","romaji":"Tuan ssineun jigeum mueoseul hamnikka?","ch":8},{"id":"l_08_02","q":"지금 몇 시입니까?","audio":"지금 몇 시예요? 열한 시예요. 열두 시 삼⽍ 분에 점심을 먹어요.","a":["10:00","11:00","12:30","01:30"],"c":"11:00","ex":"Audio menyebutkan saat ini jam 11 tepat (열한 시).","romaji":"Jigeum myeot si-imnikka?","ch":8},{"id":"l_08_03","q":"남자는 언제 운동을 합니까?","audio":"리한 씨, 보통 언제 운동해요? 저는 아침에 일찍 운동해요. 그리고 저녑에는 집에서 쉬어요.","a":["아침","점심","오후","새벽"],"c":"아침","ex":"Rihan menyatakan dia berolahraga di pagi hari (아침).","romaji":"Namjaneun eonje undongeul hamnikka?","ch":8},{"id":"l_08_04","q":"여자의 일과에 대한 설명으로 맞는 것을 고르십시오.","audio":"저는 아침 읿C극 시에 일어나요. 여더극 시에 아침을 먹고 회사에 가요. 아호극 시부터 오후 여섟 시까지 일해요. 퇴근 후에 집에서 저녑을 먹고 텔레비전을 봐요. 밤 열한 시에 자요.","a":["오전 8시에 일을 시작합니다","오후 6시에 퇴근합니다","오후 7시에 일어난니다","밤 10시에 장니다"],"c":"오후 6시에 퇴근합니다","ex":"Pembicara mengatakan dia bekerja sampai jam 6 sore, yang berarti dia pulang (퇴근) jam 6 sore.","romaji":"Yeojayi ilgwa-e daehan seolmyeong-euro manneun geoseul goreusipsio.","ch":8},{"id":"l_08_05","q":"두 사람은 몇 시에 만납니까?","audio":"가: 우리 오늘 저녑에 같이 운동할까요? 나: 좋아요. 몇 시에 만날까요? 가: 읿C극 시에 만날까요? 나: 일극 시는 너무 빨라요. 여더극 시 삼⽍ 분에 만나요. 가: 네, 알겠습니다. 그때 봐요.","a":["07:00","08:00","08:30","09:30"],"c":"08:30","ex":"Meskipun jam 7 diajukan, mereka sepakat bertemu pada 8:30 (여더극 시 삼⽍ 분).","romaji":"Du sarameun myeot sie mannamnikka?","ch":8},{"id":"l_09_01","q":"투안 씨 가족은 몇 명입니까?","audio":"투안 씨는 가족이 몇 명이에요? 어더니하고 형하고 저, 세 명이에요.","a":["두 명","세 명","네 명","다섯 명"],"c":"세 명","ex":"Tuan menyebutkan keluarganya ada 3 orang (세 명).","romaji":"Tuan ssi gajogeun myeot myeong-imnikka?","ch":9},{"id":"l_09_02","q":"여동생은 지금 무엇을 합니까?","audio":"여동생이 정말 예브요. 지금 어디에 있어요? 한국에 있어요. 학교에서 공부해요.","a":["요리해요","일해요","쇼핑해요","공부해요"],"c":"공부해요","ex":"Adik perempuannya sedang belajar (공부해요) di sekolah.","romaji":"Yeodongsaengeun jigeum mueoseul hamnikka?","ch":9},{"id":"l_09_03","q":"이 사람은 누구입니까?","audio":"이 사람이 누구예요? 우리 누나예요. 누나는 키가 커요. 그리고 정말 날씨해요.","a":["형","누나","여동생","남동생"],"c":"누나","ex":"Pembicara mengidentifikasi orang dalam foto sebagai kakak perempuannya (누나).","romaji":"I sarameun nugu-imnikka?","ch":9},{"id":"l_09_04","q":"가족에 대한 설명으로 맞는 것을 고르십시오.","audio":"우리 가족은 네 명이에요. 아버지하고 어더니는 인도네시아에 살아요. 형은 한국에서 일해요. 그리고 저는 지금 기숙사에 있어요. 저는 동생이 없어요.","a":["가족이 모두 한국에 삵니다","형은 인도네시아에 있습니다","저는 남동생이 있습니다","아버지는 인도네시아에 사십니다"],"c":"아버지는 인도네시아에 사십니다","ex":"Audio menyatakan ayah dan ibu tinggal di Indonesia (인도네시아에 살아요).","romaji":"Gajoge daehan seolmyeong-euro manneun geoseul goreusipsio.","ch":9},{"id":"l_09_05","q":"남동생의 특징이 아닌 것을 고르십시오.","audio":"제 남동생을 소개할게요. 남동생은 스무 살이에요. 아주 뚜뚜해요. 그리고 활발해서 운동을 정말 좋아해요. 하지만 조금 얄전한 성격도 있어요. 키는 조금 작아요.","a":["뚜뚜합니다","운동을 좋아합니다","키가 아주 큩니다","스무 살입니다"],"c":"키가 아주 큩니다","ex":"Pembicara menyebutkan adiknya pendek (키는 조금 작아요), jadi \"sangat tinggi\" adalah salah.","romaji":"Namdongsaengui teukjing-i anin geoseul goreusipsio.","ch":9},{"id":"l_10_01","q":"투안 씨는 언제 한국에 왔습니까?","audio":"투안 씨는 언제 한국에 왔어요? 올해 이월 십일에 왔어요. 수루 씨는요?","a":["작년 7월","올해 2월 10일","올해 3월 10일","내년 1월"],"c":"올해 2월 10일","ex":"Tuan datang tanggal 10 Februari tahun ini (올해 2월 10일).","romaji":"Tuan ssineun eonje Hanguge wasseumnikka?","ch":10},{"id":"l_10_02","q":"어제 무엇을 했습니까?","audio":"리한 씨, 어제 뭐 했어요? 친구하고 PC방에서 게임했어요. 투안 씨는요?","a":["도서관에서 공부했어요","공원에서 산책했어요","PC방에서 게임했어요","극장에서 영화를 뵌어요"],"c":"PC방에서 게임했어요","ex":"Rihan bermain game di warnet (PC방에서 게임했어요).","romaji":"Eoje mueoseul haesseumnikka?","ch":10},{"id":"l_10_03","q":"여자는 오늘 무엇을 합니까?","audio":"오늘은 친구를 만나요. 커피숲에서 같이 커피를 마셔요. 그리고 백화점에서 쇼핑할 거예요.","a":["책을 읽어요","노래해요","커피를 마셔요","영화를 봐요"],"c":"커피를 마셔요","ex":"Wanita tersebut akan minum kopi (커피를 마셔요) di kafe.","romaji":"Yeojaneun oneul mueoseul hamnikka?","ch":10},{"id":"l_10_04","q":"남자의 지난주 일과를 순서대로 고르십시오.","audio":"지난주는 정말 바빠쎈어요. 월요일에는 도서관에서 한국어를 공부했어요. 수요일에는 친구하고 영화관에서 영화를 뵌어요. 그리고 토요일에는 백화점에서 가족 선물을 ฼어요. 일요일에는 집에서 푸국 쉼었어요.","a":["공부 - 영화 - 쇼핑 - 휴식","쇼핑 - 공부 - 영화 - 운동","영화 - 쇼핑 - 공부 - 산책","공부 - 운동 - 영화 - 쇼핑"],"c":"공부 - 영화 - 쇼핑 - 휴식","ex":"Urutan kegiatannya adalah: belajar (공부), nonton film (영화), belanja (쇼핑/฼어요), dan istirahat (휴식/쉼었어요).","romaji":"Namjayi jinanju ilgwareul sunseodaero goreusipsio.","ch":10},{"id":"l_10_05","q":"대화 내용과 일치하는 것을 고르십시오.","audio":"가: 투안 씨, 어제 어디에 갔어요? 나: 공원에 갔어요. 공원에서 산책하고 운동했어요. 리한 씨는요? 가: 저는 도서관에 갔어요. 도서관에서 한국어를 공부했어요. 나: 시험이 언제예요? 가: 다음 주 금요일이에요. 그래서 열심히 공부하고 있어요.","a":["투안 씨는 어제 도서관에 갔습니다","리한 씨는 어제 운동을 했습니다","시험은 다음 주 금요일입니다","두 사람은 어제 같이 공부했습니다"],"c":"시험은 다음 주 금요일입니다","ex":"Rihan menyatakan ujiannya adalah Jumat depan (다음 주 금요일).","romaji":"Daehwa naeyong-gwa ilchihaneun geoseul goreusipsio.","ch":10},{"id":"l_11_01","q":"남자는 무엇을 얼마나 삽니까?","audio":"주인: 어서 오세요. 뭘 드릴까요? 손님: 사과 다섯 개 주세요. 그리고 물 두 병 주세요.","a":["사과 세 개, 물 한 병","사과 다섯 개, 물 두 병","사과 다섯 개, 물 세 병","사과 두 개, 물 다섯 병"],"c":"사과 다섯 개, 물 두 병","ex":"Pembicara meminta 5 buah apel dan 2 botol air.","romaji":"Namjaneun mueoseul eolmana samnikka?","ch":11},{"id":"l_11_02","q":"오렌지는 모두 얼마입니까?","audio":"가: 오렌지 얼마예요? 나: 한 개에 천 원이에요. 가: 그럼 오렌지 다섯 개 주세요.","a":["천 원","삼천 원","오천 원","만 원"],"c":"오천 원","ex":"Harga satu jeruk 1.000 won, beli 5 = 5.000 won.","romaji":"Orenjineun modu eolmaimnikka?","ch":11},{"id":"l_11_03","q":"여자는 무엇을 부탁합니까?","audio":"가: 봉투에 넣어 드릴까요? 나: 네, 봉투에 좀 넣어 주세요. 그리고 이 빵 좀 포장해 주세요.","a":["환불해 주세요","바꿔 주세요","깎아 주세요","넣어 주세요"],"c":"넣어 주세요","ex":"Wanita meminta barang dimasukkan ke kantong.","romaji":"Yeojaneun mueoseul butakhamnikka?","ch":11},{"id":"l_11_04","q":"대화 내용과 같은 것을 고르십시오.","audio":"손님: 사장님, 이 운동화 얼마예요? 주인: 오만 오천 원이에요. 손님: 오만 오천 원요? 좀 비싸요. 깎아 주세요. 주인: 그래요? 알았어요. 오만 원만 주세요. 손님: 고맙습니다. 여기 지폐로 오만 원 있어요.","a":["운동화는 오만 원입니다","손님은 값을 깎았습니다","주인은 깎아 주지 않았습니다","손님은 신용카드로 계산했습니다"],"c":"손님은 값을 깎았습니다","ex":"Pembeli minta diskon, dari 55.000 jadi 50.000 won.","romaji":"Daehwa naeyonggwa gateun geoseul goreusipsio.","ch":11},{"id":"l_11_05","q":"들은 내용으로 알맞지 않은 것을 고르십시오.","audio":"가: 어서 오세요. 뭘 드릴까요? 나: 수박 있어요? 가: 네, 있어요. 수박 한 통에 이만 원이에요. 나: 수박이 너무 비싸네요. 포도는 얼마예요? 가: 포도는 한 송이에 오천 원이에요. 나: 그럼 포도 두 송이 주세요. 여기 만 원 있습니다.","a":["수박 한 통에 이만 원입니다","포도는 한 송이에 오천 원입니다","남자는 수박 한 통을 샀습니다","남자는 모두 만 원을 냈습니다"],"c":"남자는 수박 한 통을 샀습니다","ex":"Pria tidak jadi beli semangka, beli 2 anggur 10.000 won.","romaji":"Deureun naeyong-euro almaji anneun geoseul goreusipsio.","ch":11},{"id":"l_12_01","q":"은행은 어디에 있습니까?","audio":"투안: 이 건물에 은행이 있어요? 여자: 네, 있어요. 지하 1층에 있어요. 지하로 내려가세요.","a":["1층","2층","지하 1층","건물 밖"],"c":"지하 1층","ex":"Bank di lantai 1 bawah tanah.","romaji":"Eunhengeun eodie isseumnikka?","ch":12},{"id":"l_12_02","q":"약국은 어디에 있습니까?","audio":"수루: 이 근처에 약국이 있어요? 남자: 네, 저기 병원이 보여요? 약국은 병원 옆에 있어요.","a":["병원 위","병원 옆","병원 뒤","병원 안"],"c":"병원 옆","ex":"Apotek di samping rumah sakit.","romaji":"Yakgugeun eodie isseumnikka?","ch":12},{"id":"l_12_03","q":"남자는 어디로 가야 합니까?","audio":"가: 우체국이 어디에 있어요? 나: 저 사거리에서 오른쪽으로 가세요. 그러면 우체국이 있어요.","a":["왼쪽","오른쪽","앞으로","뒤로"],"c":"오른쪽","ex":"Belok kanan di perempatan.","romaji":"Namjaneun eodiro gaya hamnikka?","ch":12},{"id":"l_12_04","q":"대화 내용과 일치하는 것을 고르십시오.","audio":"가: 실례합니다. 이 건물에 편의점이 있어요? 나: 네, 3층에 있어요. 가: 어떻게 가요? 나: 저기 계단으로 올라가세요. 그러면 식당 옆에 편의점이 있어요. 가: 아, 네. 감사합니다.","a":["편의점은 2층에 있습니다","편의점은 식당 옆에 있습니다","편의점은 건물 밖에 있습니다","계단으로 내려가야 합니다"],"c":"편의점은 식당 옆에 있습니다","ex":"Minimarket lantai 3 sebelah restoran.","romaji":"Daehwa naeyong-gwa ilchihaneun geoseul goreusipsio.","ch":12},{"id":"l_12_05","q":"남자는 지금 어디에 있습니까?","audio":"여: 투안 씨, 어디예요? 남: 저는 지금 기숙사 1층에 있어요. 세탁실에서 빨래를 하고 있어요. 여: 그래요? 저는 2층 휴게실에 있어요. 1층으로 내려오세요. 같이 식당에 가요. 남: 네, 알겠어요. 지금 갈게요.","a":["1층 세탁실","2층 휴게실","지하 주차장","건물 밖"],"c":"1층 세탁실","ex":"Tuan di ruang laundry lantai 1.","romaji":"Namjaneun jigeum eodie isseumnikka?","ch":12},{"id":"l_13_01","q":"두 사람은 내일 무엇을 합니까?","audio":"투안: 수루 씨, 내일 시간 있어요? 우리 같이 영화 볼까요? 수루: 좋아요. 같이 영화 봐요.","a":["쇼핑해요","운동해요","영화를 봐요","한국어를 공부해요"],"c":"영화를 봐요","ex":"Mereka janji nonton film.","romaji":"Du sarameun naeil mueoseul hamnikka?","ch":13},{"id":"l_13_02","q":"두 사람은 어디에서 만납니까?","audio":"가: 우리 내일 어디에서 만날까요? 나: 백화점 앞에서 볼까요? 가: 좋아요. 거기에서 만나요.","a":["시청 앞","회사 앞","극장 앞","백화점 앞"],"c":"백화점 앞","ex":"Sepakat di depan department store.","romaji":"Du sarameun eodie-seo mannamnikka?","ch":13},{"id":"l_13_03","q":"여자는 무엇을 하고 싶어합니까?","audio":"가: 오늘 뭐 하고 싶어요? 나: 날씨가 좋으니까 공원에서 같이 산책하고 싶어요.","a":["노래하고 싶어요","쇼핑하고 싶어요","산책하고 싶어요","게임하고 싶어요"],"c":"산책하고 싶어요","ex":"Ingin jalan-jalan karena cuaca bagus.","romaji":"Yeojaneun mueoseul hago sipeohamnikka?","ch":13},{"id":"l_13_04","q":"두 사람의 약속에 대한 설명으로 맞는 것을 고르십시오.","audio":"남: 수루 씨, 오늘 저녁에 같이 밥 먹을까요? 여: 미안해요. 오늘은 좀 바빠요. 내일은 어때요? 남: 내일도 괜찮아요. 그럼 내일 저녁 일곱 시에 만날까요? 여: 일곱 시는 좀 빨라요. 여덟 시에 시청 앞에서 봐요. 남: 네, 좋아요. 내일 봐요.","a":["오늘 저녁에 만납니다","내일 일곱 시에 만납니다","내일 여덟 시에 만납니다","회사 앞에서 만납니다"],"c":"내일 여덟 시에 만납니다","ex":"Batal hari ini, sepakat besok jam 8 di depan balai kota.","romaji":"Du saramui yaksoge daehan seolmyeong-euro manneun geoseul goreusipsio.","ch":13},{"id":"l_13_05","q":"여자는 내일 무엇을 할 것입니까?","audio":"남: 수루 씨, 내일 뭐 할 거예요? 친구하고 영화 볼 거예요? 여: 아니요, 영화는 어제 봤어요. 내일은 은행에 가고 싶어요. 남: 은행에는 왜요? 여: 고향에 돈을 보내야 해서 환전을 하려고 해요. 그 후에 친구를 만나서 쇼핑할 거예요.","a":["영화를 봅니다","환전을 합니다","요리를 합니다","한국어를 공부합니다"],"c":"환전을 합니다","ex":"Ke bank untuk menukar uang.","romaji":"Yeojaneun naeil mueoseul hal geosimnikka?","ch":13},{"id":"l_14_01","q":"식당에 몇 명이 왔습니까?","audio":"종업원: 어서 오세요. 몇 분이세요? 투안: 두 명이요. 자리 있어요? 종업원: 네, 있어요. 이쪽으로 앉으세요.","a":["한 명","두 명","세 명","네 명"],"c":"두 명","ex":"Tamu menjawab 'dua orang'.","romaji":"Sikdange myeot myeongi wasseumnikka?","ch":14},{"id":"l_14_02","q":"리한 씨는 무엇을 주문했습니까?","audio":"종업원: 뭐 드릴까요? 리한: 저는 비빔밥 먹을래요. 투안 씨는 뭐 먹을래요? 투안: 저는 김치찌개 먹을래요.","a":["김치찌개","된장찌개","비빔밥","갈비탕"],"c":"비빔밥","ex":"Rihan spesifik pesan bibimbap.","romaji":"Rihan ssineun mueoseul jumun-haesseumnikka?","ch":14},{"id":"l_14_03","q":"김치찌개 맛이 어때요?","audio":"가: 김치찌개가 안 매워요? 나: 조금 매워요. 하지만 정말 맛있어요. 가: 그래요? 그럼 저도 다음에 먹어 볼게요.","a":["달아요","짜요","매워요","시어요"],"c":"매워요","ex":"Agak pedas tapi enak.","romaji":"Gimchijjigae masi eottaeyo?","ch":14},{"id":"l_14_04","q":"두 사람이 주문한 음식은 모두 무엇입니까?","audio":"종업원: 어서 오세요. 뭐 드릴까요? 손님 1: 여기 메뉴판 좀 주세요. 음... 저는 갈비탕 먹을래요. 수미 씨는요? 손님 2: 저는 어제 갈비탕을 먹었어요. 그래서 오늘은 비빔밥을 먹을래요. 손님 1: 사장님, 여기 갈비탕 하나하고 비빔밥 하나 주세요.","a":["갈비탕 두 그릇","비빔밥 두 그릇","갈비탕 한 그릇, 비빔밥 한 그릇","김치찌개 한 그릇, 갈비탕 한 그릇"],"c":"갈비탕 한 그릇, 비빔밥 한 그릇","ex":"Galbitang + bibimbap.","romaji":"Du sarami jumun-han eumsigeun modu mueosimnikka?","ch":14},{"id":"l_14_05","q":"대화 내용과 다른 것을 고르십시오.","audio":"리한: 투안 씨는 김치찌개를 좋아해요? 투안: 네, 정말 좋아해요. 리한 씨는요? 리한: 아니요, 저는 안 좋아해요. 저는 매운 음식을 안 좋아해요. 하지만 불고기는 정말 좋아해요. 불고기는 아주 달고 맛있어요.","a":["투안 씨는 김치찌개를 좋아합니다.","리한 씨는 매운 음식을 좋아하지 않습니다.","투안 씨는 불고기를 주문했습니다.","불고기는 맛이 답니다."],"c":"투안 씨는 불고기를 주문했습니다.","ex":"Rihan yang suka bulgogi, bukan Tuan.","romaji":"Daehwa naeyong-gwa dareun geoseul goreusipsio.","ch":14},{"id":"l_15_01","q":"오늘 날씨는 어떻습니까?","audio":"투안: 오늘 날씨가 참 좋네요. 수루: 네, 요즘은 날씨가 따뜻해서 기분이 정말 좋아요.","a":["추워요","흐려요","더워요","따뜻해요"],"c":"따뜻해요","ex":"Cuaca disebut hangat.","romaji":"Oneul nalssineun eotteoseumnikka?","ch":15},{"id":"l_15_02","q":"남자는 왜 기분이 좋습니까?","audio":"가: 투안 씨, 기분이 어때요? 나: 정말 좋아요. 눈이 와서 기분이 아주 좋아요.","a":["비가 와서","눈이 와서","날씨가 더워서","시험을 잘 쳐서"],"c":"눈이 와서","ex":"Senang karena turun salju.","romaji":"Namjaneun wae gibuni jouseumnikka?","ch":15},{"id":"l_15_03","q":"지금은 무슨 계절입니까?","audio":"가: 지금 날씨가 어때요? 나: 너무 더워요. 비도 많이 와요.","a":["봄","여름","가을","겨울"],"c":"여름","ex":"Panas + banyak hujan = musim panas.","romaji":"Jigeumeun museun gyejeol-imnikka?","ch":15},{"id":"l_15_04","q":"대화 내용과 다른 것을 고르십시오.","audio":"가: 수미 씨는 무슨 계절을 좋아해요? 나: 저는 여름을 좋아해요. 투안 씨는요? 가: 저는 봄을 좋아해요. 날씨가 따뜻해서 좋아요. 나: 그렇군요. 그런데 오늘 날씨는 너무 흐리네요. 가: 네, 비가 올 것 같아요. 비가 오면 기분이 좀 우울해요.","a":["남자는 봄을 좋아합니다","여자는 여름을 좋아합니다","오늘 날씨는 아주 맑습니다","남자는 비가 오면 기분이 안 좋습니다"],"c":"오늘 날씨는 아주 맑습니다","ex":"Hari ini mendung, bukan cerah.","romaji":"Daehwa naeyong-gwa dareun geoseul goreusipsio.","ch":15},{"id":"l_15_05","q":"남자는 오늘 왜 피곤합니까?","audio":"여: 투안 씨, 얼굴이 안 좋네요. 무슨 일 있어요? 남: 아니요, 어제 일을 많이 해서 좀 피곤해요. 여: 그래요? 그럼 오늘은 일찍 집에 가서 쉬세요. 남: 네, 그러고 싶어요. 어제 잠도 못 자서 지금 너무 졸려요.","a":["비가 와서","일을 많이 해서","운동을 많이 해서","날씨가 너무 더워서"],"c":"일을 많이 해서","ex":"Lelah karena banyak kerja dan kurang tidur.","romaji":"Namjaneun oneul wae pigonhamnikka?","ch":15},{"id":"l_16_01","q":"투안 씨는 시간이 있을 때 보통 무엇을 합니까?","audio":"수루 씨, 저는 낚시를 정말 좋아해요. 그래서 시간이 있을 때 낚시하러 자주 가요. 수루 씨는 취미가 뭐예요?","a":["등산을 합니다","독서를 합니다","낚시를 합니다","여행을 합니다"],"c":"낚시를 합니다","ex":"Tuan menyatakan bahwa hobinya adalah memancing dan sering pergi memancing saat ada waktu luang.","romaji":"Tuan ssineun sigani isseul ttae botong mueoseul hamnikka?","ch":16},{"id":"l_16_02","q":"여자는 기분이 좋을 때 무엇을 합니까?","audio":"저는 기분이 좋을 때 노래를 불러요. 노래를 부르면 마음이 정말 즐거워져요. 리한 씨는 어때요?","a":["춤을 춥니다","노래를 부릅니다","잠을 잡니다","음악을 듣습니다"],"c":"노래를 부릅니다","ex":"Wanita tersebut menjelaskan bahwa ia bernyanyi (노래를 불러요) ketika merasa senang.","romaji":"Yeojaneun gibuni joeul ttae mueoseul hamnikka?","ch":16},{"id":"l_16_03","q":"두 사람은 이번 주말에 무엇을 하겠습니까?","audio":"가: 이번 주말에 시간이 있어요? 같이 테니스 치러 갈래요? 나: 좋아요. 같이 가요. 저도 테니스를 배우고 싶었어요.","a":["축구를 합니다","테니스를 칩니다","등산을 합니다","자전거를 탑니다"],"c":"테니스를 칩니다","ex":"Mereka sepakat untuk pergi bermain tenis bersama (테니스 치러 갈래요) pada akhir pekan.","romaji":"Du sarameun ibon jumare mueoseul hagetseumnikka?","ch":16},{"id":"l_16_04","q":"외국인력지원센터의 프로그램에 대한 설명으로 맞는 것은 무엇입니까?","audio":"안녕하세요. 우리 센터에서는 외국인들을 위한 다양한 교육 프로그램을 운영하고 있습니다. 한국어 수업은 매주 토요일에 있고, 컴퓨터 수업은 일요일 오후에 있습니다. 그리고 태권도를 배우고 싶은 분들은 평일 저녁에 오시면 됩니다. 모든 수업은 무료입니다.","a":["한국어 수업은 일요일에 있습니다.","컴퓨터 수업은 토요일에 있습니다.","태권도 수업은 평일 저녁에 있습니다.","모든 수업은 돈을 내야 합니다."],"c":"태권도 수업은 평일 저녁에 있습니다.","ex":"Pengumuman menyatakan kelas Taekwondo diadakan pada malam hari di hari kerja (평일 저녁).","romaji":"Oegugin-illyeok-jiwon-senteoyi peurogeuraeme daehan seolmyeong-euro manneun geoseun mueosimnikka?","ch":16},{"id":"l_16_05","q":"남자의 취미 활동에 대한 내용으로 알맞은 것을 고르십시오.","audio":"제 취미는 사진 찍기입니다. 주말마다 친구들하고 같이 아름다운 경치를 찍으러 여행을 가요. 지난주에는 제주도에 가서 바다 사진을 많이 찍었어요. 사진을 찍을 때 기분이 정말 행복해요. 나중에 사진가가 되고 싶어요.","a":["혼자서 여행하는 것을 좋아합니다.","지난주에 산에 가서 사진을 찍었습니다.","사진 찍는 것이 남자의 취미입니다.","주말에는 집에서 음악을 듣습니다."],"c":"사진 찍는 것이 남자의 취미입니다.","ex":"Pria tersebut menjelaskan bahwa hobinya adalah mengambil foto (사진 찍기) dan ia merasa bahagia saat melakukannya.","romaji":"Namjayi chwimi hwaldonge daehan naeyong-euro almajeun geoseul goreusipsio.","ch":16},{"id":"l_17_01","q":"리한 씨는 제주도에 가 봤습니까?","audio":"투안: 리한 씨는 제주도에 가 봤어요? 리한: 네, 가 봤어요. 제주도는 바다가 너무 아름다웠어요.","a":["아니요, 안 가 봤어요.","네, 가 봤어요.","내년에 갈 거예요.","어제 갔어요."],"c":"네, 가 봤어요.","ex":"Rihan menjawab \"Ya, sudah pernah\" (네, 가 봤어요) ketika ditanya tentang kunjungannya ke Pulau Jeju.","romaji":"Rihan ssineun Jejudo-e ga bwasseumnikka?","ch":17},{"id":"l_17_02","q":"남자는 이번 휴가 때 무엇을 할 것입니까?","audio":"이번 여름 휴가 때 친구들하고 설악산에 갈 거예요. 거기에서 등산도 하고 사진도 많이 찍을 거예요. 벌써 기차 표도 샀어요.","a":["바다에 갑니다","설악산에 갑니다","제주도에 갑니다","집에 있습니다"],"c":"설악산에 갑니다","ex":"Pria tersebut berencana pergi ke Gunung Seorak (설악산) pada liburan kali ini.","romaji":"Namjaneun ibon hyuga ttae mueoseul hal geosimnikka?","ch":17},{"id":"l_17_03","q":"남자는 여행을 위해 무엇을 준비했습니까?","audio":"가: 투안 씨, 여행 준비 다 했어요? 나: 네, 비행기 표도 사고 숙소도 벌써 다 예약했어요. 짐만 싸면 돼요.","a":["기념품","등산복","표와 숙소 예약","사진기"],"c":"표와 숙소 예약","ex":"Tuan sudah membeli tiket pesawat dan memesan penginapan (숙소 예약).","romaji":"Namjaneun yeohaengeul wihae mueoseul junbi-haesseumnikka?","ch":17},{"id":"l_17_04","q":"대화 내용과 다른 것을 고르십시오.","audio":"여: 리한 씨, 부산 여행은 어땠어요? 남: 정말 재미있었어요. 바다가 아주 아름다웠고 맛있는 음식도 많았어요. 여: 부산에서 사진도 많이 찍었어요? 남: 네, 많이 찍었어요. 그런데 사람이 너무 많아서 조금 복잡했어요. 다음에는 평일에 가고 싶어요.","a":["부산은 바다가 아름답습니다.","부산에는 맛있는 음식이 많습니다.","남자는 사진을 한 장도 안 찍었습니다.","부산에는 사람이 많아서 복잡했습니다."],"c":"남자는 사진을 한 장도 안 찍었습니다.","ex":"Pria tersebut mengatakan ia mengambil banyak foto (많이 찍었어요), sehingga opsi C salah.","romaji":"Daehwa naeyong-gwa dareun geoseul goreusipsio.","ch":17},{"id":"l_17_05","q":"들은 내용과 일치하는 것을 고르십시오.","audio":"한국에는 아름다운 관광지가 참 많습니다. 서울에는 경복궁과 한강 유람선이 유명하고, 강원도는 산과 바다가 모두 있어서 사람들이 많이 찾습니다. 제주도는 한국에서 가장 큰 섬인데 경치가 아주 아름다워서 외국인 관광객들에게 인기가 많습니다.","a":["서울에는 경복궁이 없습니다.","제주도는 한국에서 가장 작은 섬입니다.","강원도는 산만 있고 바다는 없습니다.","제주도는 경치가 좋아서 인기가 많습니다."],"c":"제주도는 경치가 좋아서 인기가 많습니다.","ex":"Teks menyatakan Jeju sangat populer karena pemandangannya yang indah (경치가 아주 아름다워).","romaji":"Deureun naeyong-gwa ilchihaneun geoseul goreusipsio.","ch":17},{"id":"l_18_01","q":"남자는 회사에 어떻게 갑니까?","audio":"가: 집에서 회사까지 어떻게 가요? 나: 보통 버스나 지하철을 타고 가요. 오늘은 지하철을 타고 왔어요.","a":["택시를 탑니다","지하철을 탑니다","자전거를 탑니다","걸어갑니다"],"c":"지하철을 탑니다","ex":"Pria tersebut hari ini datang naik kereta bawah tanah (지하철을 타고 왔어요).","romaji":"Namjaneun hoesa-e eotteoke gamnikka?","ch":18},{"id":"l_18_02","q":"집에서 시청까지 얼마나 걸립니까?","audio":"가: 여기에서 시청까지 얼마나 걸려요? 나: 버스로 30분 정도 걸려요. 하지만 지금은 차가 막혀서 좀 더 걸릴 거예요.","a":["15분","30분","1시간","2시간"],"c":"30분","ex":"Waktu tempuh normal dengan bus adalah 30 menit (30분 정도).","romaji":"Jibeoseo sicheong-kkaji eolmana geollimnikka?","ch":18},{"id":"l_18_03","q":"남자는 어디에서 내려야 합니까?","audio":"가: 실례합니다. 서울역에 가려면 어디에서 내려요? 나: 이번 정류장에서 내리세요. 그리고 건너편에서 1번 버스로 갈아타세요.","a":["기차역","이번 정류장","지하철역","공항"],"c":"이번 정류장","ex":"Instruksinya adalah turun di halte ini (이번 정류장).","romaji":"Namjaneun eodie-seo naeryeoya hamnikka?","ch":18},{"id":"l_18_04","q":"대화 내용과 같은 것을 고르십시오.","audio":"남: 회사에 올 때 차를 가지고 와요? 여: 아니요, 출퇴근 시간에는 길에 차가 너무 많아서 버스가 너무 느려요. 남: 그래요? 저는 집이 가까워서 걸어서 와요. 여: 와, 정말 좋겠네요. 저는 지하철역까지 좀 멀어서 버스를 타고 지하철로 갈아타야 해요.","a":["남자는 회사에 차를 타고 옵니다.","여자는 회사에 걸어서 옵니다.","남자의 집은 회사에서 가깝습니다.","여자는 갈아타지 않고 지하철만 탑니다."],"c":"남자의 집은 회사에서 가깝습니다.","ex":"Pria tersebut mengatakan rumahnya dekat (집이 가까워서) sehingga ia jalan kaki.","romaji":"Daehwa naeyong-gwa gateun geoseul goreusipsio.","ch":18},{"id":"l_18_05","q":"남자가 공장에 어떻게 가는지 고르십시오.","audio":"가: 오늘 공장에 가야 하는데 본사에서 공장까지 어떻게 가요? 나: 버스 정류장에서 300번 버스를 타세요. 그리고 세 번째 정류장에서 내리세요. 거기에서 공장까지는 가까우니까 조금만 걸어가면 돼요. 택시를 타면 돈이 많이 나오니까 버스를 이용하세요.","a":["택시를 타고 갑니다.","버스를 타고 내려서 걷습니다.","본사에서 계속 걸어갑니다.","지하철을 타고 갑니다."],"c":"버스를 타고 내려서 걷습니다.","ex":"Instruksinya adalah naik bus, turun di halte ketiga, lalu jalan kaki sedikit (조금만 걸어가면 돼요).","romaji":"Namjaga gongjang-e eotteoke ganeunji goreusipsio.","ch":18},{"id":"l_19_01","q":"남자는 어디에 전화를 걸었습니까?","audio":"남: 여보세요. 거기 한국가구지요? 여: 네, 맞습니다. 무엇을 도와드릴까요?","a":["도서관","한국가구","병원","우체국"],"c":"한국가구","ex":"Pria tersebut mengonfirmasi apakah itu \"Hanguk Gagu\" (Korea Furniture) dan wanita tersebut mengiyakan.","romaji":"Namjaneun eodie jeonwhareul georeotseumnikka?","ch":19},{"id":"l_19_02","q":"여자는 왜 인터넷 쇼핑을 좋아합니까?","audio":"저는 주로 인터넷에서 옷을 많이 사요. 인터넷 쇼핑은 가격도 싸고 쇼핑도 편리해서 정말 좋아요. 수루 씨도 한번 해 보세요.","a":["옷이 예뻐서","사람이 많아서","싸고 편리해서","직접 볼 수 있어서"],"c":"싸고 편리해서","ex":"Wanita tersebut menyukai belanja online karena murah dan praktis (싸고 편리해서).","romaji":"Yeojaneun wae inteonet syoping-eul joahamnikka?","ch":19},{"id":"l_19_03","q":"남자는 지금 무엇을 하고 있습니까?","audio":"가: 투안 씨, 지금 뭐 해요? 나: 고향 친구하고 영상 통화를 하고 있어요. 오랜만에 친구 얼굴을 보니까 정말 기뻐요.","a":["문자를 보냅니다","인터넷을 합니다","영상 통화를 합니다","사진을 찍습니다"],"c":"영상 통화를 합니다","ex":"Tuan sedang melakukan panggilan video (영상 통화) dengan temannya.","romaji":"Namjaneun jigeum mueoseul hago isseumnikka?","ch":19},{"id":"l_19_04","q":"대화 내용으로 알 수 있는 것은 무엇입니까?","audio":"여: 리한 씨, 한국어 공부를 더 하고 싶은데 어디가 좋아요? 남: 외국인력지원센터에 전화해 보세요. 거기에서 무료로 가르쳐 줘요. 여: 그래요? 전화번호를 알아요? 남: 저는 잘 몰라요. 114에 전화해서 물어보세요. 아주 친절하게 안내해 줄 거예요.","a":["남자는 한국어 선생님입니다.","여자는 지금 한국어를 가르칩니다.","114에서 전화번호를 물어볼 수 있습니다.","외국인력지원센터는 수업료가 비쌉니다."],"c":"114에서 전화번호를 물어볼 수 있습니다.","ex":"Rihan menyarankan untuk menelepon 114 untuk menanyakan nomor telepon pusat bantuan.","romaji":"Daehwa naeyong-euro al su itneun geoseun mueosimnikka?","ch":19},{"id":"l_19_05","q":"인터넷 가입에 대한 설명으로 맞는 것을 고르십시오.","audio":"한국 사이트에 회원 가입을 하려면 몇 가지 정보가 필요합니다. 먼저 아이디와 비밀번호를 정해야 합니다. 그리고 외국인의 경우에는 외국인등록번호가 꼭 있어야 가입할 수 있는 사이트가 많습니다. 가입이 끝나면 로그인해서 서비스를 이용하면 됩니다.","a":["아이디는 필요 없습니다.","외국인은 가입할 수 없습니다.","가입할 때 외국인등록번호가 필요할 수 있습니다.","로그인을 먼저 해야 가입이 됩니다."],"c":"가입할 때 외국인등록번호가 필요할 수 있습니다.","ex":"Disebutkan bahwa bagi orang asing, seringkali diperlukan nomor registrasi asing (외국인등록번호) untuk mendaftar.","romaji":"Inteonet gaibe daehan seolmyeong-euro manneun geoseul goreusipsio.","ch":19},{"id":"l_20_01","q":"남자는 무엇을 하겠습니까?","audio":"여: 방이 너무 더럽네요. 같이 청소할까요? 남: 좋아요. 제가 방을 쓸게요. 투안 씨는 먼지를 닦아 주세요.","a":["설거지를 합니다","방을 씁니다","먼지를 닦습니다","쓰레기를 버립니다"],"c":"방을 씁니다","ex":"Pria tersebut menawarkan diri untuk menyapu kamar (제가 방을 쓸게요).","romaji":"Namjaneun mueoseul hagetseumnikka?","ch":20},{"id":"l_20_02","q":"여자는 왜 요리하는 것을 싫어합니까?","audio":"저는 요리하는 것을 별로 안 좋아해요. 요리하는 것은 너무 어렵고 복잡해요. 그래서 보통 밖에서 밥을 사 먹어요.","a":["시간이 없어서","돈이 많이 들어서","어렵고 복잡해서","설거지가 힘들어서"],"c":"어렵고 복잡해서","ex":"Wanita tersebut menganggap memasak itu sulit dan rumit (어렵고 복잡해요).","romaji":"Yeojaneun wae yorihaneun geoseul sileohamnikka?","ch":20},{"id":"l_20_03","q":"지금 방 상태가 어떠합니까?","audio":"가: 리한 씨, 방이 왜 이렇게 지저분해요? 나: 어제 청소를 안 해서 그래요. 지금 바로 정리할게요.","a":["깨끗합니다","넓습니다","지저분합니다","조용합니다"],"c":"지저분합니다","ex":"Kamar dikatakan berantakan atau kotor (지저분해요) karena belum dibersihkan.","romaji":"Jigeum bang sangtaega eotteohamnikka?","ch":20},{"id":"l_20_04","q":"두 사람의 대화 내용과 같은 것을 고르십시오.","audio":"남: 수미 씨, 오늘 저녁에 제가 친구들을 초대했어요. 그래서 음식 준비를 좀 해야 해요. 여: 그래요? 그럼 제가 도와줄게요. 저는 장을 보러 갈게요. 남: 고마워요. 그럼 저는 그동안 집안 청소를 하고 음식을 만들게요. 여: 네, 알겠어요. 조금 이따가 마트에서 봐요.","a":["여자가 음식을 직접 만듭니다.","남자가 마트에 가서 장을 봅니다.","두 사람은 오늘 저녁에 같이 청소를 합니다.","여자가 마트에서 장을 보기로 했습니다."],"c":"여자가 마트에서 장을 보기로 했습니다.","ex":"Wanita tersebut (Sumi) menawarkan diri untuk pergi belanja keperluan (장을 보러 갈게요) ke mart.","romaji":"Du saramui daehwa naeyong-gwa gateun geoseul goreusipsio.","ch":20},{"id":"l_20_05","q":"리한 씨가 투안 씨에게 부탁한 것은 무엇입니까?","audio":"투안 씨, 저 리한이에요. 제가 오늘 아침에 옥상에 제 바지를 널었어요. 그런데 갑자기 비가 올 것 같아요. 저는 지금 밖이라서 기숙사에 못 들어가요. 투안 씨가 제 바지를 좀 걷어 주세요. 부탁해요. 고마워요.","a":["바지를 세탁해 주는 것","바지를 사다 주는 것","옥상에서 바지를 걷어 주는 것","방을 청소해 주는 것"],"c":"옥상에서 바지를 걷어 주는 것","ex":"Rihan meminta Tuan untuk mengangkat jemuran celananya (바지를 좀 걷어 주세요) karena akan turun hujan.","romaji":"Rihan ssiga Tuan ssiege butakhan geoseun mueosimnikka?","ch":20},{"id":"l_21_01","q":"남자는 왜 여기에 왔습니까?","audio":"남: 안녕하세요. 저는 아딧입니다. 사장님하고 2시에 약속이 있어서 왔습니다.","a":["선물을 사러 왔습니다","사장님을 만나러 왔습니다","집을 찾으러 왔습니다","음식을 장만하러 왔습니다"],"c":"사장님을 만나러 왔습니다","ex":"Pria tersebut (Adit) datang karena memiliki janji dengan direktur pada pukul 2 siang.","romaji":"Namjaneun wae yeogie wasseumnikka? / Annyeonghaseyo. Jeoneun Adit-imnida. Sajangnimhago dusi-e yaksogi isseoseo wasseumnida.","ch":21},{"id":"l_21_02","q":"여자는 무엇을 준비했습니까?","audio":"여: 어서 오세요. 초대에 응해 주셔서 감사합니다. 제가 갈비하고 잡채를 많이 장만했습니다. 어서 드세요.","a":["세제와 휴지","수저와 식기","갈비와 잡채","화분과 시계"],"c":"갈비와 잡채","ex":"Wanita tersebut mengatakan telah menyiapkan (장만하다) galbi dan japchae untuk tamunya.","romaji":"Yeojaneun mueoseul junbi-haesseumnikka? / Eoseo oseyo. Chodae-e eung-hae jusyeoseo gamsahamnida. Jega galbihago japchaereul mani jangman-haesseumnida. Eoseo deuseyo.","ch":21},{"id":"l_21_03","q":"두 사람은 지금 무엇을 하고 있습니까?","audio":"가: 수미 씨, 제가 상 차리는 것을 좀 도와줄까요? 나: 네, 고마워요. 그럼 이 수저를 상 위에 놓아 주세요.","a":["음식을 만듭니다","상을 차립니다","상을 치웁니다","이야기를 나눕니다"],"c":"상을 차립니다","ex":"Mereka sedang menata meja makan (상 차리다) dengan meletakkan alat makan di atas meja.","romaji":"Du sarameun jigeum mueoseul hago isseumnikka?","ch":21},{"id":"l_21_04","q":"들은 내용과 일치하는 것을 고르십시오.","audio":"가: 모니카 씨, 내일 우리 집에 올 수 있어요? 제가 이번에 이사를 해서 집들이를 하거든요. 나: 정말요? 축하해요. 선물은 뭐가 좋을까요? 가: 선물은 괜찮아요. 그냥 오세요. 나: 아니에요. 한국에서는 집들이 선물로 세제나 휴지를 많이 사 가는데 저도 세제를 준비할게요.","a":["남자는 내일 친구 집에 갑니다.","여자는 이번에 이사를 했습니다.","남자는 집들이 선물로 화분을 삽니다.","여자는 내일 집들이를 합니다."],"c":"여자는 내일 집들이를 합니다.","ex":"Monika (wanita) mengadakan acara syukuran pindah rumah (집들이) dan mengundang temannya.","romaji":"Deureun naeyonggwa ilchihaneun geoseul goreusipsio.","ch":21},{"id":"l_21_05","q":"대화 내용과 다른 것을 고르십시오.","audio":"남: 아딧 씨, 사장님께 연락 드렸어요? 아까 잠깐 밖에 나가셨거든요. 여: 네, 아까 통화했어요. 2시에 사무실에서 뵙기로 했어요. 남: 그렇군요. 그럼 제가 커피 한 잔 드릴까요? 날씨가 많이 추운데 따뜻한 커피를 마시면서 기다리세요. 여: 네, 감사합니다. 사장님을 기다리는 동안 여기에 있을게요.","a":["여자는 사장님과 약속이 있습니다.","사장님은 지금 사무실에 계십니다.","남자는 여자에게 커피를 주려고 합니다.","지금 밖의 날씨는 춥습니다."],"c":"사장님은 지금 사무실에 계십니다.","ex":"Dalam audio disebutkan direktur sedang keluar sebentar (잠깐 밖에 나가셨어요), jadi pernyataan bahwa direktur ada di kantor adalah salah.","romaji":"Daehwa naeyonggwa dareun geoseul goreusipsio.","ch":21},{"id":"l_22_01","q":"남자는 여자에게 무엇을 하면 안 된다고 말합니까?","audio":"여: 차가 안 와요. 빨리 건너가요. 남: 여기에서 길을 건너면 안 돼요. 저기 횡단보도로 가세요.","a":["차를 타면 안 됩니다","뛰어가면 안 됩니다","무단 횡단을 하면 안 됩니다","사진을 찍으면 안 됩니다"],"c":"무단 횡단을 하면 안 됩니다","ex":"Pria melarang menyeberang sembarangan (길을 건너면 안 돼요) dan menyarankan menggunakan zebra cross.","romaji":"Namjaneun yeojage mueoseul hamyeon an doendago malhamnikka?","ch":22},{"id":"l_22_02","q":"이곳에서 할 수 없는 행동은 무엇입니까?","audio":"이곳은 주차 금지 구역입니다. 여기에 차를 세우면 안 됩니다. 주차장을 이용해 주세요.","a":["금연","음식물 반입","주차","휴대전화 사용"],"c":"주차","ex":"Audio menyatakan daerah tersebut dilarang parkir (주차 금지).","romaji":"Igoseoseo hal su eomneun haengdongeun mueosimnikka?","ch":22},{"id":"l_22_03","q":"남자가 지하철을 타려는 이유는 무엇입니까?","audio":"가: 지금 차가 많이 막히네요. 나: 네, 지금은 퇴근 시간이라서 그래요. 차가 막히니까 지하철을 타고 갑시다.","a":["지하철이 빨라서","길이 막히니까","돈이 없어서","운동을 하려고"],"c":"길이 막히니까","ex":"Pria tersebut menyarankan naik kereta bawah tanah karena jalanan macet (차가 막히니까).","romaji":"Namjaga jihacheoreul taryeoneun iyuneun mueosimnikka?","ch":22},{"id":"l_22_04","q":"다음 중 들은 내용과 일치하는 표지판은 무엇입니까?","audio":"여러분, 안내 말씀 드립니다. 우리 미술관 안에서는 사진 촬영이 금지되어 있습니다. 사진을 찍으면 안 됩니다. 그리고 음식물 반입도 안 되니까 밖에서 다 드시고 들어오십시오. 마지막으로 큰 소리로 떠들면 다른 사람들에게 방해가 됩니다. 조용히 관람해 주세요.","a":["주차 금지","사진 촬영 금지","휴대전화 사용 금지","접근 금지"],"c":"사진 촬영 금지","ex":"Pengumuman di galeri seni melarang pengambilan foto (사진 촬영 금지), membawa makanan, dan berisik.","romaji":"Daeum jung deureun naeyonggwa ilchihaneun pyojipaneun mueosimnikka?","ch":22},{"id":"l_22_05","q":"대화 내용과 다른 것을 고르십시오.","audio":"여: 투안 씨, 극장 안에서 담배를 피우면 안 돼요. 남: 아, 그래요? 몰랐어요. 죄송합니다. 여: 여기는 금연 구역이니까 담배를 피우고 싶으면 건물 밖으로 나가야 돼요. 남: 네, 알겠습니다. 지금 바로 나갈게요. 여: 그리고 극장 안에서는 음식물도 가지고 들어오면 안 돼요.","a":["남자는 극장 안에서 담배를 피웠습니다.","극장 안은 담배를 피울 수 없는 곳입니다.","남자는 건물 밖에서 음식을 먹어야 합니다.","극장 안에서 음식을 먹어도 됩니다."],"c":"극장 안에서 음식을 먹어도 됩니다.","ex":"Wanita tersebut mengatakan tidak boleh membawa makanan ke dalam bioskop (음식물도 가지고 들어오면 안 돼요), sehingga opsi D salah.","romaji":"Daehwa naeyonggwa dareun geoseul goreusipsio.","ch":22},{"id":"l_23_01","q":"여자는 한국 친구 집에 갈 때 무엇을 물어봤습니까?","audio":"여: 지훈 씨, 제가 한국 친구 집에 초대를 받았는데 어른이 계시는 집이라서 좀 걱정돼요. 어른들께 어떤 선물을 드리면 좋을까요?","a":["밥을 먹는 방법","드려야 할 선물","신발을 신는 방법","자리를 양보하는 방법"],"c":"드려야 할 선물","ex":"Pembicara wanita bertanya tentang hadiah apa yang sebaiknya diberikan kepada orang tua di rumah temannya.","romaji":"Yeojaneun Hanguk chingu jibe gal ttae mueoseul mureobwasseumnikka?","ch":23},{"id":"l_23_02","q":"어른께 물건을 드릴 때 어떻게 해야 합니까?","audio":"한국에서는 어른께 물건을 드릴 때 두 손으로 드려야 합니다. 한 손으로 드리면 예의가 아닙니다.","a":["한 손으로 드립니다","두 손으로 드립니다","던져서 드립니다","허리를 숙이지 않습니다"],"c":"두 손으로 드립니다","ex":"Etika di Korea saat memberikan barang kepada orang tua adalah menggunakan dua tangan (두 손으로 드려야 합니다).","romaji":"Eoreunkke mulgeoneul deuril ttae eotteoke haeya hamnikka?","ch":23},{"id":"l_23_03","q":"지하철에서 해야 할 행동으로 알맞은 것은 무엇입니까?","audio":"지하철이나 버스에서 어른을 뵈면 자리를 양보해야 합니다. 자리를 차지하고 앉아 있으면 안 됩니다.","a":["자리를 양보합니다","큰 소리로 전화합니다","신발을 벗습니다","음식을 먹습니다"],"c":"자리를 양보합니다","ex":"Di transportasi umum, seseorang harus memberikan kursi (자리를 양보하다) kepada orang tua.","romaji":"Jihacheoreoseo haeya hal haengdong-euro almajeun geoseun mueosimnikka?","ch":23},{"id":"l_23_04","q":"들은 내용과 다른 것을 고르십시오.","audio":"한국의 식사 예절에 대해 알려 드릴게요. 어른과 함께 식사할 때는 어른이 먼저 숟가락을 드실 때까지 기다려야 합니다. 그리고 밥그릇을 들고 먹으면 안 됩니다. 식사가 끝난 후에는 숟가락과 젓가락을 식탁 위에 놓으면 됩니다.","a":["어른보다 먼저 밥을 먹으면 안 됩니다.","밥그릇을 들고 식사를 해야 합니다.","식사 후 수저를 식탁 위에 놓습니다.","어른이 식사를 시작할 때까지 기다립니다."],"c":"밥그릇을 들고 식사를 해야 합니다.","ex":"Dalam audio disebutkan tidak boleh mengangkat mangkuk nasi saat makan (밥그릇을 들고 먹으면 안 됩니다).","romaji":"Deureun naeyonggwa dareun geoseul goreusipsio.","ch":23},{"id":"l_23_05","q":"남자의 아버지는 어떤 분입니까?","audio":"가: 투안 씨, 이 사진에 있는 분이 아버지세요? 나: 네, 우리 아버지예요. 가: 아버지가 키가 정말 크시네요. 나: 네, 키가 크고 아주 멋있으세요. 지금은 고향에서 사세요. 작년에 한국에 오셨을 때 같이 여행도 했어요.","a":["지금 한국에 살고 계십니다.","키가 작으신 편입니다.","지금 고향에 살고 계십니다.","작년에 아들과 여행을 안 했습니다."],"c":"지금 고향에 살고 계십니다.","ex":"Tuan mengatakan ayahnya sekarang tinggal di kampung halaman (지금은 고향에서 사세요).","romaji":"Namjayi abeojineun eotteon bun-imnikka?","ch":23},{"id":"l_24_01","q":"여자는 한국어를 어떻게 공부합니까?","audio":"여: 저는 한국 영화 보는 것을 좋아해서 한국 영화를 보면서 공부해요. 수피카 씨도 좋아하는 것을 하면서 공부해 보세요.","a":["학원에 다닙니다","사전만 찾습니다","영화를 보면서 공부합니다","친구와 이야기만 합니다"],"c":"영화를 보면서 공부합니다","ex":"Wanita tersebut menjelaskan bahwa ia belajar bahasa Korea sambil menonton film.","romaji":"Yeojaneun hangugeoreul eotteoke gongbu-hamnikka?","ch":24},{"id":"l_24_02","q":"한국어 수업이 언제 있습니까?","audio":"우리 센터에서는 외국인 근로자를 위한 한국어 수업이 있습니다. 수업은 매주 일요일 오후 3시부터 5시까지입니다.","a":["토요일 오전","토요일 오후","일요일 오전","일요일 오후"],"c":"일요일 오후","ex":"Kelas bahasa Korea diadakan setiap hari Minggu sore (일요일 오후).","romaji":"Hangugeo sueobi eonje isseumnikka?","ch":24},{"id":"l_24_03","q":"남자는 왜 자동차 정비 교육을 받으려고 합니까?","audio":"저는 나중에 고향에 돌아가서 일을 구할 때 도움이 될 것 같아서 자동차 정비 교육을 신청했어요. 수업이 아주 재미있어요.","a":["한국 영화가 좋아서","취업에 도움이 될 것 같아서","한국 친구를 만나려고","시간이 너무 많아서"],"c":"취업에 도움이 될 것 같아서","ex":"Tuan mengambil pelatihan servis mobil karena menganggap itu akan membantu saat mencari kerja di kampung halaman nanti.","romaji":"Namjaneun wae jadongcha jeongbi gyoyugeul badeuryeogo hamnikka?","ch":24},{"id":"l_24_04","q":"대화 내용으로 알 수 있는 것은 무엇입니까?","audio":"남: 흐엉 씨, 한국어 공부하기가 어때요? 여: 한국어 단어가 너무 어려워서 그러는데 공부하기가 쉽지 않아요. 남: 그래요? 그럼 모르는 단어는 사전을 찾으면서 공부해 보세요. 그리고 인터넷 강의를 듣는 것도 도움이 돼요. 여: 고마워요. 저도 인터넷 강의를 한번 들어 볼게요.","a":["여자는 한국어 공부가 아주 쉽습니다.","남자는 여자에게 사전을 찾으라고 합니다.","여자는 이미 인터넷 강의를 듣고 있습니다.","두 사람은 지금 영화관에 있습니다."],"c":"남자는 여자에게 사전을 찾으라고 합니다.","ex":"Pria menyarankan untuk belajar sambil mencari kata sulit di kamus (사전을 찾으면서 공부해 보세요).","romaji":"Daehwa naeyong-euro al su itneun geoseun mueosimnikka?","ch":24},{"id":"l_24_05","q":"교육 프로그램 신청 순서로 맞는 것을 고르십시오.","audio":"교육 프로그램을 신청하려면 먼저 홈페이지에서 어떤 수업이 있는지 찾아보세요. 그 다음에 수업 시간과 장소를 확인하고 신청 버튼을 누르세요. 개인 정보를 입력하고 나서 '보내기'를 클릭하면 신청이 끝납니다. 나중에 이메일로 결과를 확인할 수 있습니다.","a":["정보 입력 - 수업 검색 - 장소 확인","수업 검색 - 장소 확인 - 정보 입력","이메일 확인 - 신청 버튼 클릭 - 수업 검색","신청 버튼 클릭 - 이메일 확인 - 정보 입력"],"c":"수업 검색 - 장소 확인 - 정보 입력","ex":"Urutan pendaftaran adalah mencari kelas (찾아보세요), cek waktu/tempat (확인하고), lalu masukkan data diri (정보를 입력).","romaji":"Gyoyuk peurogeuraem sincheong sunseoro manneun geoseul goreusipsio.","ch":24},{"id":"l_25_01","q":"리리 씨는 일요일에 무엇을 합니까?","audio":"여: 미영 씨, 미안해요. 일요일에는 제가 교회에 가야 돼요. 일요일마다 교회에 가서 예배를 드리거든요.","a":["쇼핑을 합니다","영화를 봅니다","교회에 갑니다","회사에 갑니다"],"c":"교회에 갑니다","ex":"Riri (wanita) mengatakan setiap hari Minggu ia harus pergi ke gereja untuk beribadah.","romaji":"Riri ssineun iryo-ire mueoseul hamnikka?","ch":25},{"id":"l_25_02","q":"아딧 씨는 종교가 무엇입니까?","audio":"아딧 씨는 인도네시아 사람입니다. 하루에 다섯 번씩 기도를 드립니다. 시간이 나면 이태원에 있는 이슬람 사원에 갑니다.","a":["불교","기독교","천주교","이슬람교"],"c":"이슬람교","ex":"Adit berdoa 5 kali sehari dan pergi ke masjid (이슬람 사원), maka agamanya adalah Islam.","romaji":"Adit ssineun jonggyoga mueosimnikka?","ch":25},{"id":"l_25_03","q":"지하철은 몇 분마다 옵니까?","audio":"가: 여기에서 시청에 가려면 지하철이 자주 와요? 나: 네, 출퇴근 시간에는 사람이 많아서 삼 분마다 와요. 잠시만 기다리세요.","a":["1분마다","3분마다","5분마다","10분마다"],"c":"3분마다","ex":"Kereta bawah tanah datang setiap 3 menit (삼 분마다) pada jam sibuk.","romaji":"Jihacheoreun myeot bun-mada omnikka?","ch":25},{"id":"l_25_04","q":"들은 내용과 일치하지 않는 것을 고르십시오.","audio":"가: 미영 씨는 종교가 있어요? 나: 부모님이 불교 신자라서 저도 어릴 때는 절에 다녔어요. 그런데 요즘은 바빠서 잘 안 가요. 가: 그렇군요. 저는 일요일마다 성당에 가서 미사를 드려요. 성당에 가면 마음이 참 편안해져요.","a":["여자의 부모님은 불교를 믿습니다.","남자는 일요일마다 성당에 갑니다.","여자는 요즘도 절에 자주 다닙니다.","남자는 성당에 가면 기분이 좋아집니다."],"c":"여자는 요즘도 절에 자주 다닙니다.","ex":"Miyeong (wanita) mengatakan dulu sering ke kuil tapi sekarang jarang pergi karena sibuk (요즘은 바빠서 잘 안 가요).","romaji":"Deureun naeyonggwa ilchihaji anneun geoseul goreusipsio.","ch":25},{"id":"l_25_05","q":"여자의 소원은 무엇입니까?","audio":"저는 한국에서 일하면서 돈을 많이 벌었으면 좋겠어요. 그래서 고향에 있는 가족들에게 큰 집을 사 주고 싶어요. 그리고 우리 가족 모두가 아프지 않고 건강하게 살았으면 좋겠어요. 내년에는 꼭 고향에 가서 가족들을 만나고 싶어요.","a":["돈을 많이 버는 것","혼자 한국에서 사는 것","일을 그만두는 것","내년에 여행을 안 가는 것"],"c":"돈을 많이 버는 것","ex":"Wanita tersebut berharap bisa menghasilkan banyak uang (돈을 많이 벌었으면 좋겠어요) untuk keluarganya.","romaji":"Yeojayi sowoneun mueosimnikka?","ch":25},{"id":"l_26_01","q":"바루 씨는 어디가 아픕니까?","audio":"약사: 어떻게 오셨어요? 바루: 머리가 아파서 왔어요. 약사: 언제부터 아프셨어요? 바루: 어젯밤부터요.","a":["배가 아픕니다","머리가 아픕니다","다리가 아픕니다","이가 아픕니다"],"c":"머리가 아픕니다","ex":"Dalam percakapan, Baru menjawab \"머리가 아파서 왔어요\" yang berarti dia datang karena sakit kepala.","romaji":"Baru ssineun eodiga apeumnikka? / Yaksa: Eotteoke osyeosseoyo? Baru: Meoriga apaseo wasseoyo. Yaksa: Eonjebuteo apeusyeosseoyo? Baru: Eojetbambuteoyo.","ch":26},{"id":"l_26_02","q":"여자는 오늘 무엇을 먹으면 안 됩니까?","audio":"모니카 씨, 오늘 아침부터 배가 많이 아파요? 그럼 이 약을 드세요. 그리고 오늘은 유제품은 먹지 마세요.","a":["고기","과일","우유","채소"],"c":"우유","ex":"Apoteker menyarankan agar Monika tidak mengonsumsi produk olahan susu (유제품) seperti susu.","romaji":"Yeojaneun oneul mueoseul meogeumyeon an doemnikka?","ch":26},{"id":"l_26_03","q":"이 약은 언제 먹어야 합니까?","audio":"가: 이 약은 언제 먹어야 돼요? 나: 밥을 먹은 후에 드세요. 하루에 세 번 드시면 됩니다.","a":["식사 전에","식사 후에","잠자기 전에","아침에만"],"c":"식사 후에","ex":"Instruksi dalam audio menyatakan obat harus diminum setelah makan (밥을 먹은 후에).","romaji":"I yageun eonje meogeoya hamnikka?","ch":26},{"id":"l_26_04","q":"바루 씨가 머리가 아픈 이유는 무엇입니까?","audio":"약사: 언제부터 아프셨어요? 바루: 어젯밤부터요. 어제 저녁에 회식이 있어서 술을 좀 마셨어요. 약사: 아, 술 때문에 그런 것 같네요. 밥을 먹은 후에 이 약을 드세요. 바루: 네, 감사합니다.","a":["어제 일을 많이 해서","어제 술을 마셔서","아침을 안 먹어서","감기에 걸려서"],"c":"어제 술을 마셔서","ex":"Apoteker menyimpulkan Baru sakit kepala karena minum alkohol (술 때문에) saat acara makan malam kantor kemarin.","romaji":"Baru ssiga meoriga apeun iyuneun mueosimnikka?","ch":26},{"id":"l_26_05","q":"대화 내용과 일치하는 것을 고르십시오.","audio":"반장님, 저 모니카예요. 오늘 너무 아파서 회사에 못 갑니다. 어제 저녁부터 배가 아프고 계속 설사를 했어요. 어제 약국에서 약을 사 먹었는데 아직도 아파요. 오늘 아침에는 열도 나서 오늘은 집에서 쉬려고 해요. 죄송합니다.","a":["모니카 씨는 오늘 회사에 갔습니다.","모니카 씨는 어제 약을 안 먹었습니다.","모니카 씨는 배가 아프고 열이 납니다.","모니카 씨는 오늘 약국에 갈 겁니다."],"c":"모니카 씨는 배가 아프고 열이 납니다.","ex":"Monika sakit perut, diare sejak kemarin, dan pagi ini juga demam (열도 나서), sehingga dia izin tidak masuk kerja.","romaji":"Daehwa naeyong-gwa ilchihaneun geoseul goreusipsio.","ch":26},{"id":"l_27_01","q":"투안 씨는 어디가 아픕니까?","audio":"리한: 투안 씨, 걷는 게 왜 그래요? 투안: 발목이 좀 아파요. 어제 계단에서 넘어졌거든요.","a":["손목","발목","허리","어깨"],"c":"발목","ex":"Tuan mengatakan pergelangan kakinya (발목) sakit karena jatuh di tangga kemarin.","romaji":"Tuan ssineun eodiga apeumnikka?","ch":27},{"id":"l_27_02","q":"남자는 어디에 가야 합니까?","audio":"가: 목이 너무 아파요. 나: 목이 아프면 이비인후과에 가 보세요. 저기 지하철역 근처에 있어요.","a":["치과","안과","내과","이비인후과"],"c":"이비인후과","ex":"Untuk sakit tenggorokan (목), disarankan pergi ke klinik THT (이비인후과).","romaji":"Namjaneun eodie gaya hamnikka?","ch":27},{"id":"l_27_03","q":"남자는 무엇을 했습니까?","audio":"어제 요리를 하다가 손을 데었어요. 그래서 연고를 바르고 밴드를 붙였어요.","a":["주사를 맞았습니다","붕대를 감았습니다","밴드를 붙였습니다","수술을 했습니다"],"c":"밴드를 붙였습니다","ex":"Pria tersebut mengoleskan salep dan menempelkan plester (밴드를 붙였어요) setelah tangannya terkena panas saat memasak.","romaji":"Namjaneun mueoseul haesseumnikka?","ch":27},{"id":"l_27_04","q":"대화 내용과 다른 것을 고르십시오.","audio":"여: 어떻게 오셨습니까? 남: 넘어져서 발목을 삐었어요. 여: 어디 봅시다. 여기가 아픕니까? 남: 아! 네. 여: 발목에 파스를 붙이시고 많이 걷지 마세요. 그리고 집에서 찜질을 하셔야 됩니다. 남: 네, 알겠습니다.","a":["남자는 발목을 다쳤습니다.","남자는 많이 걸어야 합니다.","남자는 집에서 찜질을 해야 합니다.","여자는 남자에게 파스를 주었습니다."],"c":"남자는 많이 걸어야 합니다.","ex":"Petugas medis melarang pria tersebut banyak berjalan (많이 걷지 마세요), sehingga opsi B salah.","romaji":"Daehwa naeyong-gwa dareun geoseul goreusipsio.","ch":27},{"id":"l_27_05","q":"여자는 대화 후에 무엇을 할 것입니까?","audio":"남: 수지 씨, 근무 시간에 어디에 갔다 왔어요? 여: 죄송해요, 반장님. 점심 먹고 속이 너무 안 좋아서 휴게실에서 좀 쉬었어요. 남: 많이 아프면 일찍 들어가서 약 먹고 좀 쉬도록 해요. 여: 네, 반장님. 그렇게 할게요. 감사합니다.","a":["계속 일을 합니다.","점심을 먹으러 갑니다.","집에 가서 쉽니다.","병원에 가서 진찰을 받습니다."],"c":"집에 가서 쉽니다.","ex":"Karena perutnya tidak enak, mandor mengizinkan Su-ji pulang lebih awal untuk istirahat, dan Su-ji menyetujuinya.","romaji":"Yeojaneun daehwa hue mueoseul hal geosimnikka?","ch":27},{"id":"l_28_01","q":"리한 씨는 왜 은행에 왔습니까?","audio":"은행원: 어떻게 오셨습니까? 리한: 통장을 만들려고 왔어요. 은행원: 신분증을 가지고 오셨습니까?","a":["돈을 찾으려고","환전하려고","통장을 만들려고","송금하려고"],"c":"통장을 만들려고","ex":"Rihan secara eksplisit menyatakan tujuannya adalah membuat buku tabungan atau rekening (통장을 만들려고).","romaji":"Rihan ssineun wae eunhenge wasseumnikka?","ch":28},{"id":"l_28_02","q":"남자는 오늘 무엇을 합니까?","audio":"오늘은 월급날이에요. 그래서 은행에 가서 고향으로 돈을 보내려고 해요. 송금 수수료가 적은 은행을 찾고 있어요.","a":["가입을 합니다","송금을 합니다","출금을 합니다","조회를 합니다"],"c":"송금을 합니다","ex":"Karena hari ini hari gajian, pria tersebut ingin mengirim uang ke kampung halaman (송금).","romaji":"Namjaneun oneul mueoseul hamnikka?","ch":28},{"id":"l_28_03","q":"환전을 하려면 어디에 가야 합니까?","audio":"가: 한국 돈을 베트남 돈으로 바꾸고 싶어요. 나: 환전을 하려면 회사 앞에 있는 은행에 가 보세요. 저도 거기에서 했어요.","a":["병원","우체국","도서관","은행"],"c":"은행","ex":"Disarankan pergi ke bank (은행) untuk menukar mata uang (환전).","romaji":"Hwanjeoneul haryeomeun eodie gaya hamnikka?","ch":28},{"id":"l_28_04","q":"은행에서 통장을 만들 때 필요한 것은 무엇입니까?","audio":"은행에 가서 통장을 만들려면 신분증이 필요합니다. 외국인은 외국인등록증이나 여권이 있으면 됩니다. 신분증을 보여주고 신청서를 씁니다. 그리고 서명을 하면 통장이 나옵니다.","a":["휴대 전화","신용카드","신분증","사진기"],"c":"신분증","ex":"Untuk membuat rekening, diperlukan kartu identitas (신분증) seperti kartu registrasi asing atau paspor.","romaji":"Eunhengeseo tongjangeul mandeul ttae piryohan geoseun mueosimnikka?","ch":28},{"id":"l_28_05","q":"오늘은 무슨 요일입니까?","audio":"여: 은행에요? 오늘은 일요일인데 고향으로 송금할 수 있어요? 남: 네. 우리 동네 은행은 일하는 외국인들이 많아서 일요일에도 문을 열어요. 그래서 지금 가려고 해요.","a":["월요일","토요일","일요일","금요일"],"c":"일요일","ex":"Wanita tersebut mengonfirmasi bahwa hari ini adalah hari Minggu (일요일) dan bertanya apakah bank tetap buka.","romaji":"Oneureun museun yoirimnikka?","ch":28},{"id":"l_29_01","q":"모니카 씨는 무엇을 보냅니까?","audio":"우체국 직원: 어떻게 오셨습니까? 모니카: 엽서를 보내고 싶은데요. 필리핀으로 보낼 겁니다.","a":["편지","소포","엽서","카드"],"c":"엽서","ex":"Monika ingin mengirim kartu pos (엽서) ke Filipina.","romaji":"Monika ssineun mueoseul bonemnikka?","ch":29},{"id":"l_29_02","q":"소포를 보내려면 상자를 어디에 놓아야 합니까?","audio":"베트남으로 소포를 보내려고 하는데요. 네, 그럼 상자를 저울에 올려놓으십시오. 무게를 재야 합니다.","a":["책상 위","저울 위","의자 위","바닥 위"],"c":"저울 위","ex":"Petugas meminta agar kotak diletakkan di atas timbangan (저울에 올려놓으십시오) untuk diukur beratnya.","romaji":"Soporeul boneryeomyeon sangjareul eodie noaya hamnikka?","ch":29},{"id":"l_29_03","q":"항공편으로 보내면 시간이 얼마나 걸립니까?","audio":"베트남까지 얼마나 걸릴까요? 배편은 한두 달 정도 걸리고 항공편은 열흘에서 이 주 정도 걸립니다.","a":["한두 달","삼 일","오 일","열흘에서 이 주"],"c":"열흘에서 이 주","ex":"Pengiriman melalui pesawat (항공편) memakan waktu 10 hari sampai 2 minggu (열흘에서 이 주).","romaji":"Hanggongpyeoneuro bonemyeon sigani eolmana geollimnikka?","ch":29},{"id":"l_29_04","q":"남자가 우체국에 온 이유는 무엇입니까?","audio":"여: 어떻게 오셨어요? 남: 중국으로 소포를 보내려고 합니다. 여: 안에 무엇이 있습니까? 남: 옷하고 책이 있어요. 여: 그럼 여기 저울 위에 올려놓으세요.","a":["소포를 받으려고","소포를 보내려고","친구를 만나려고","옷을 사려고"],"c":"소포를 보내려고","ex":"Pria tersebut datang untuk mengirim paket (소포를 보내려고) berisi pakaian dan buku ke Cina.","romaji":"Namjaga ucheguge on iyuneun mueosimnikka?","ch":29},{"id":"l_29_05","q":"대화 내용과 일치하는 것을 고르십시오.","audio":"여: 베트남으로 엽서를 보내려고 하는데 얼마나 걸릴까요? 남: 국제 특급은 사 일 정도 걸리고 일반 우편은 칠 일에서 십 일 정도 걸려요. 여: 그럼 국제 특급으로 할게요. 남: 네, 여기에 주소를 쓰십시오.","a":["국제 특급은 칠 일이 걸립니다.","일반 우편이 국제 특급보다 빠릅니다.","여자는 일반 우편으로 보낼 겁니다.","국제 특급은 사 일 정도 걸립니다."],"c":"국제 특급은 사 일 정도 걸립니다.","ex":"Berdasarkan audio, EMS (국제 특급) memakan waktu sekitar 4 hari, sedangkan pos biasa 7-10 hari.","romaji":"Daehwa naeyong-gwa ilchihaneun geoseul goreusipsio.","ch":29},{"id":"l_30_01","q":"남자는 왜 센터에 전화했습니까?","audio":"리한: 여보세요. 거기 외국인력지원센터지요? 태권도를 배우고 싶은데 수업을 들을 수 있어요?","a":["태권도를 배우고 싶어서","한국 음식을 만들고 싶어서","친구를 찾고 싶어서","병원을 예약하고 싶어서"],"c":"태권도를 배우고 싶어서","ex":"Rihan menelepon karena ingin belajar taekwondo (태권도를 배우고 싶어서).","romaji":"Namjaneun wae senteoe jeonwhahaesseumnikka?","ch":30},{"id":"l_30_02","q":"태권도 수업은 무슨 요일에 있습니까?","audio":"네, 우리 센터에서는 매주 일요일에 태권도 수업이 있어요. 전혀 할 수 없어도 괜찮으니까 오셔서 상담을 받아 보세요.","a":["토요일","일요일","월요일","금요일"],"c":"일요일","ex":"Kelas taekwondo diadakan setiap hari Minggu (일요일).","romaji":"Taegwondo sueobeun museun yoire isseumnikka?","ch":30},{"id":"l_30_03","q":"교육을 신청하려면 무엇을 해야 합니까?","audio":"가: 한국어 교육을 신청하려고 하는데 어떻게 해야 돼요? 나: 그럼 먼저 이 신청서를 쓰고 잠깐만 기다리세요.","a":["돈을 냅니다","신청서를 씁니다","전화를 합니다","사진을 찍습니다"],"c":"신청서를 씁니다","ex":"Untuk mendaftar, langkah pertamanya adalah mengisi formulir pendaftaran (신청서를 쓰고).","romaji":"Gyoyugeul sincheongharyeomyeon mueoseul haeya hamnikka?","ch":30},{"id":"l_30_04","q":"외국인력지원센터에서 할 수 없는 것은 무엇입니까?","audio":"안녕하세요. 우리 센터에서는 외국인 근로자들을 위해 다양한 프로그램을 운영합니다. 한국어와 컴퓨터를 배울 수 있고 태권도 수업도 있습니다. 또한 무료 진료와 법률 상담도 받을 수 있으니 많이 이용해 주세요.","a":["컴퓨터 배우기","법률 상담 받기","비행기 표 사기","무료 진료 받기"],"c":"비행기 표 사기","ex":"Pusat bantuan menyediakan program bahasa, komputer, taekwondo, medis, dan hukum, tetapi tidak disebutkan layanan pembelian tiket pesawat.","romaji":"Oegugin-illyeok-jiwon-senteo-eseo hal su eomneun geoseun mueosimnikka?","ch":30},{"id":"l_30_05","q":"무료 진료는 언제 받을 수 있습니까?","audio":"안내 말씀 드립니다. 우리 센터에서는 매월 둘째 일요일 오후 두 시에 무료 진료를 실시합니다. 내과, 치과, 한방 진료를 받을 수 있으니 아픈 분들은 회의실로 오시기 바랍니다. 감사합니다.","a":["매주 화요일 오전 11시","매월 둘째 일요일 오후 2시","매일 오후 2시","매주 일요일 오전 10시"],"c":"매월 둘째 일요일 오후 2시","ex":"Pengumuman menyatakan pemeriksaan gratis dilakukan setiap hari Minggu kedua setiap bulan jam 2 siang (매월 둘째 일요일 오후 두 시).","romaji":"Muryo jinryoneun eonje badeul su isseumnikka?","ch":30},{"id":"l_31_01","q":"바루 씨의 고향 날씨는 어떠합니까?","audio":"바루 씨, 밖을 보세요. 지금 눈이 와요. 우리 고향은 일 년 내내 더워요. 그래서 눈이 오지 않아요. 정말 신기해요.","a":["일 년 내내 따뜻합니다","일 년 내내 덥습니다","겨울에 눈이 많이 옵니다","서울보다 기온이 낮습니다"],"c":"일 년 내내 덥습니다","ex":"Dalam audio, Baru menyatakan bahwa kampung halamannya panas sepanjang tahun (일 년 내내 더워요) sehingga tidak turun salju.","romaji":"Baru ssiyi gohyang nalssineun eotteohamnikka?","ch":31},{"id":"l_31_02","q":"남자의 고향은 서울보다 무엇이 적습니까?","audio":"우리 고향은 서울보다 인구도 적고 조용해요. 그래서 처음 서울에 왔을 때는 사람이 너무 많아서 깜짝 놀랐어요.","a":["인구","건물","자동차","공기"],"c":"인구","ex":"Pembicara menyebutkan bahwa kampung halamannya memiliki populasi yang lebih sedikit (인구도 적고) dibandingkan Seoul.","romaji":"Namjayi gohyangeun Seoul-boda mueosi jeokseumnikka?","ch":31},{"id":"l_31_03","q":"오늘 기온은 몇 도까지 올라갑니까?","audio":"오늘 날씨가 어때요? 어제보다 시원해요. 최고기온은 22도이고 최저기온은 15도예요.","a":["15도","22도","25도","30도"],"c":"22도","ex":"Audio menyatakan suhu tertinggi (최고기온) hari ini adalah 22 derajat.","romaji":"Oneul gioneun myeot dokkaji ollagamnikka?","ch":31},{"id":"l_31_04","q":"대화 내용과 다른 것을 고르십시오.","audio":"택시 기사: 어디에서 오셨어요? 칸: 캄보디아에서 왔어요. 기사: 아, 저도 여행을 가 봤는데 정말 좋았어요. 공기도 맑고 조용하고요. 칸: 네, 우리 고향은 인구도 적고 한적해요. 서울은 사람이 너무 많아서 복잡한 것 같아요.","a":["칸 씨는 캄보디아 사람입니다.","칸 씨의 고향은 공기가 맑습니다.","서울은 캄보디아보다 인구가 많습니다.","택시 기사는 캄보디아에 안 가 봤습니다."],"c":"택시 기사는 캄보디아에 안 가 봤습니다.","ex":"Sopir taksi mengatakan dia pernah berwisata ke sana (저도 여행을 가 봤는데), sehingga opsi D salah.","romaji":"Daehwa naeyong-gwa dareun geoseul goreusipsio.","ch":31},{"id":"l_31_05","q":"보라카이 날씨에 대한 설명으로 맞는 것은 무엇입니까?","audio":"보라카이는 일 년 내내 따뜻합니다. 평균 기온은 25도 정도이고 영하로 내려가는 날이 없습니다. 7월과 8월에는 비가 많이 오지만 11월부터는 습도가 낮아서 여행하기에 아주 좋습니다.","a":["1월에는 눈이 많이 옵니다.","일 년 내내 습도가 높습니다.","7월에는 비가 많이 옵니다.","평균 기온이 영하입니다."],"c":"7월에는 비가 많이 옵니다.","ex":"Audio menyatakan pada bulan Juli dan Agustus hujan turun deras (7월과 8월에는 비가 많이 오지만).","romaji":"Borakai nalssie daehan seolmyeong-euro manneun geoseun mueosimnikka?","ch":31},{"id":"l_32_01","q":"한국 사람들은 여름에 왜 삼계탕을 먹습니까?","audio":"날씨가 더운데 왜 뜨거운 삼계탕을 먹어요? 여름에 뜨거운 음식을 먹으면 몸이 따뜻해져서 더위를 이길 수 있어요.","a":["요리하기 쉬워서","맛이 달기 때문에","더위를 이기기 위해서","가격이 저렴해서"],"c":"더위를 이기기 위해서","ex":"Memakan makanan panas di musim panas membantu menghangatkan tubuh agar bisa mengalahkan hawa panas (더위를 이길 수 있어요).","romaji":"Hanguk saramdeureun yeoreume wae samgyetangeul meokseumnikka?","ch":32},{"id":"l_32_02","q":"김치찌개를 만들 때 마지막에 무엇을 넣습니까?","audio":"먼저 김치하고 돼지고기를 볶으세요. 그 다음에 물을 넣고 끓이세요. 물이 끓으면 양파와 파를 넣으세요.","a":["돼지고기","김치","식용유","양파와 파"],"c":"양파와 파","ex":"Berdasarkan cara masak, bawang bombay dan daun bawang (양파와 파) dimasukkan setelah air mendidih.","romaji":"Gimchijjigaereul mandeul ttae majimage mueoseul neokseumnikka?","ch":32},{"id":"l_32_03","q":"두 사람은 무엇을 주문했습니까?","audio":"어느 식당에 갈까요? 저기 사람이 많은 식당에 들어가요. 그럼 불고기만 2인분 주세요. 공깃밥 두 그릇하고요.","a":["삼계탕 2인분","김치찌개 2인분","불고기 2인분과 밥","냉면 2그릇"],"c":"불고기 2인분과 밥","ex":"Pria tersebut memesan 2 porsi bulgogi dan 2 mangkuk nasi (불고기 2인분... 공깃밥 두 그릇).","romaji":"Du sarameun mueoseul jumun-haesseumnikka?","ch":32},{"id":"l_32_04","q":"한국의 식사 예절에 대한 설명으로 맞는 것은 무엇입니까?","audio":"한국 사람들은 식사를 할 때 밥과 함께 국이나 찌개, 그리고 여러 가지 반찬을 같이 먹어요. 이때 밥하고 국, 찌개는 숟가락으로 먹고 반찬은 젓가락으로 먹어요. 숟가락과 젓가락을 모두 사용해요.","a":["국은 젓가락으로 먹습니다.","밥을 먹을 때 숟가락을 사용합니다.","반찬은 숟가락으로만 먹습니다.","빵과 우유를 주로 먹습니다."],"c":"밥을 먹을 때 숟가락을 사용합니다.","ex":"Nasi, sup, dan jjigae dimakan menggunakan sendok (숟가락으로 먹고).","romaji":"Hangukui siksa yejeore daehan seolmyeong-euro manneun geoseun mueosimnikka?","ch":32},{"id":"l_32_05","q":"김치찌개 조리 방법으로 일치하지 않는 것은 무엇입니까?","audio":"김치찌개를 맛있게 끓이는 방법을 알려 줄게요. 먼저 김치와 돼지고기를 적당하게 써세요. 냄비에 김치와 고기를 넣고 식용유와 함께 볶으세요. 고기가 익으면 물을 넣고 끓이세요. 마지막에 양파와 파를 넣으면 끝납니다.","a":["고기를 먼저 볶습니다.","물이 끓기 전에 양파를 넣습니다.","김치를 적당한 크기로 썹니다.","냄비에 물을 넣고 끓입니다."],"c":"물이 끓기 전에 양파를 넣습니다.","ex":"Bawang bombay dimasukkan setelah air mendidih (물이 끓으면), bukan sebelum, sehingga opsi B salah.","romaji":"Gimchijjigae jori bangbeop-euro ilchihaji anneun geoseun mueosimnikka?","ch":32},{"id":"l_33_01","q":"남자는 이번 명절에 무엇을 할 것입니까?","audio":"지훈 씨는 이번 명절에 뭐 할 거예요? 해마다 고향에 다녀왔는데 이번에는 집에 있으려고요. 일도 많고 연휴도 짧아서 못 갈 것 같아요.","a":["고향에 갑니다","집에서 쉽니다","친구를 만납니다","여행을 갑니다"],"c":"집에서 쉽니다","ex":"Karena pekerjaan banyak dan libur singkat, Ji-hoon memutuskan untuk tetap di rumah (집에 있으려고요).","romaji":"Namjaneun ibon myeongjeore mueoseul hal geosimnikka?","ch":33},{"id":"l_33_02","q":"설날에 하는 행동이 아닌 것은 무엇입니까?","audio":"설날 아침에는 한복을 입고 어른들께 세배를 해요. 그리고 가족들과 같이 떡국을 먹어요. 아이들은 세뱃돈을 받기도 해요.","a":["세배를 합니다","떡국을 먹습니다","한복을 입습니다","송편을 빚습니다"],"c":"송편을 빚습니다","ex":"Membuat Songpyeon (송편) biasanya dilakukan saat Chuseok, sedangkan audio hanya menyebutkan Sebae, Tteokguk, dan Hanbok untuk Seollal.","romaji":"Seollare haneun haengdong-i anin geoseun mueosimnikka?","ch":33},{"id":"l_33_03","q":"여자는 추석 연휴에 어디에 가려고 합니까?","audio":"수피카 씨, 추석 연휴에 뭐 할 거예요? 저는 친구들하고 경복궁에 가려고 해요. 거기에서 여러 가지 행사를 하거든요.","a":["고향 집","경복궁","박물관","놀이공원"],"c":"경복궁","ex":"Heong berencana pergi ke Istana Gyeongbokgung bersama teman-temannya.","romaji":"Yeojaneun Chuseok yeonhue eodie garyeogo hamnikka?","ch":33},{"id":"l_33_04","q":"대화 내용과 일치하는 것을 고르십시오.","audio":"여: 지훈 씨, 이번 명절에 고향에 안 가요? 남: 네, 이번 연휴는 너무 짧아서 그냥 집에 있기로 했어요. 여: 아쉽겠네요. 남: 괜찮아요. 친구들하고 같이 한국 음식을 만들어 먹을 거예요. 흐엉 씨는요? 여: 저는 고향에 다녀올 거예요.","a":["두 사람은 같이 고향에 갑니다.","남자는 이번 연휴에 일을 합니다.","여자는 이번 명절에 고향에 갑니다.","남자는 혼자서 떡국을 먹을 겁니다."],"c":"여자는 이번 명절에 고향에 갑니다.","ex":"Wanita (Heong) mengatakan dia akan pergi ke kampung halaman (저는 고향에 다녀올 거예요).","romaji":"Daehwa naeyong-gwa ilchihaneun geoseul goreusipsio.","ch":33},{"id":"l_33_05","q":"한국의 추석에 대한 설명으로 맞는 것은 무엇입니까?","audio":"추석은 한국의 큰 명절 중 하나입니다. 추석에는 고향에 내려가는 사람들이 많아서 기차 표를 미리 사야 합니다. 가족들이 모여서 햇곡식으로 만든 음식을 먹고 송편을 빚습니다. 밤에는 보름달을 보면서 소원을 빕니다.","a":["추석에는 떡국을 꼭 먹어야 합니다.","추석에는 달을 보며 소원을 빕니다.","추석 연휴에는 기차 표를 사기 쉽습니다.","추석은 한국에서 가장 추운 날입니다."],"c":"추석에는 달을 보며 소원을 빕니다.","ex":"Saat Chuseok, orang-orang melihat bulan purnama dan berdoa/meminta harapan (보름달을 보면서 소원을 빕니다).","romaji":"Hangukui Chuseok-e daehan seolmyeong-euro manneun geoseun mueosimnikka?","ch":33},{"id":"l_34_01","q":"여자는 남자에게 무엇을 축하한다고 말했습니까?","audio":"지훈 씨, 정말 멋있네요. 결혼 축하해요. 신부 씨도 정말 아름다워요.","a":["생일","취업","이사","결혼"],"c":"결혼","ex":"Wanita tersebut mengucapkan selamat atas pernikahan Ji-hoon (결혼 축하해요).","romaji":"Yeojaneun namja-ege mueoseul chukhahandago malhaesseumnikka?","ch":34},{"id":"l_34_02","q":"돌잔치 선물로 무엇을 많이 합니까?","audio":"오늘 저녁에 돌잔치에 같이 가실 거죠? 예전에는 보통 금반지를 많이 선물했는데 요즘에는 금값이 너무 올라서 축의금을 내기도 해요.","a":["화분","세제","금반지","휴지"],"c":"금반지","ex":"Secara tradisional, cincin emas (금반지) adalah hadiah yang umum diberikan saat ulang tahun pertama bayi.","romaji":"Doljanchi seonmul-lo mueoseul mani hamnikka?","ch":34},{"id":"l_34_03","q":"남자는 장례식에 갈 때 무슨 색 옷을 입을 것입니까?","audio":"장례식장에 갈 때는 까만색 옷을 입고 가야 돼요. 그럼 집에 가서 까만색 옷을 입고 올게요. 잠시만 기다려 주세요.","a":["하얀색","빨간색","파란색","까만색"],"c":"까만색","ex":"Untuk pergi ke pemakaman, pria tersebut akan pulang untuk berganti pakaian warna hitam (까만색 옷).","romaji":"Namjaneun jangnyesige gal ttae museun saek oseul ibeul geosimnikka?","ch":34},{"id":"l_34_04","q":"대화 내용과 다른 것을 고르십시오.","audio":"남: 오늘 저녁에 김 과장님 딸 돌잔치에 가요? 여: 네, 가야지요. 남자는 선물을 준비했어요? 남: 아니요, 아직 못 샀어요. 금반지를 살까요? 여: 요즘은 금값이 너무 비싸서 그냥 축의금을 내는 게 어때요? 남: 아, 그래요? 그럼 저도 축의금을 준비할게요.","a":["오늘 저녁에 돌잔치가 있습니다.","남자는 이미 금반지를 샀습니다.","여자는 남자에게 축의금을 추천했습니다.","요즘 금값이 많이 올랐습니다."],"c":"남자는 이미 금반지를 샀습니다.","ex":"Pria tersebut mengatakan belum membeli hadiah (아직 못 샀어요), jadi opsi B salah.","romaji":"Daehwa naeyong-gwa dareun geoseul goreusipsio.","ch":34},{"id":"l_34_05","q":"집들이 선물에 대한 설명으로 알맞은 것은 무엇입니까?","audio":"한국 사람들은 이사를 한 후에 친구들을 초대하는 집들이를 합니다. 이때 손님들은 세제나 휴지를 선물로 사 갑니다. 휴지는 일이 잘 풀리라는 의미가 있고, 세제는 거품처럼 빨리 부자가 되라는 의미가 있습니다.","a":["휴지는 부자가 되라는 의미입니다.","세제는 건강하게 살라는 의미입니다.","세제는 빨리 부자가 되라는 의미가 있습니다.","집들이 때는 선물을 절대 가져가지 않습니다."],"c":"세제는 빨리 부자가 되라는 의미가 있습니다.","ex":"Deterjen (세제) melambangkan harapan agar penerima cepat menjadi kaya (빨리 부자가 되라는 의미).","romaji":"Jipdeuri seonmure daehan seolmyeong-euro almajeun geoseun mueosimnikka?","ch":34},{"id":"l_35_01","q":"수피카 씨는 누구를 제일 좋아합니까?","audio":"수피카 씨, 한국 연예인 중에 누구를 제일 좋아해요? 저는 빅뱅을 제일 좋아해요. 노래도 잘하고 아주 멋있잖아요.","a":["엑소","빅뱅","샤이니","방탄소년단"],"c":"빅뱅","ex":"Supika menyatakan dia paling suka Big Bang (빅뱅) karena mereka keren.","romaji":"Supika ssineun nugureul jeil joahamnikka?","ch":35},{"id":"l_35_02","q":"한국의 대표적인 수출품은 무엇입니까?","audio":"한국의 대표적인 수출품은 뭐예요? 예전에는 의류나 신발을 많이 수출했지만 요즘은 자동차나 전자제품이 유명해요.","a":["가구","신발","전자제품","식료품"],"c":"전자제품","ex":"Produk ekspor representatif saat ini adalah mobil dan produk elektronik (전자제품).","romaji":"Hangukui daepyojoegin suchulpumeun mueosimnikka?","ch":35},{"id":"l_35_03","q":"여자는 왜 한국 드라마를 좋아합니까?","audio":"흐엉 씨 고향에서도 한국 드라마가 인기가 있어요? 그럼요. 한국 드라마는 이야기 속의 배우들도 멋있고 내용이 재미있잖아요.","a":["배우가 없어서","한국어가 쉬워서","내용이 재미있어서","가격이 싸서"],"c":"내용이 재미있어서","ex":"Alasan yang disebutkan adalah karena ceritanya menarik (재미있잖아요).","romaji":"Yeojaneun wae Hanguk deuramareul joahamnikka?","ch":35},{"id":"l_35_04","q":"한류 열풍과 수출의 관계에 대한 설명으로 맞는 것은 무엇입니까?","audio":"한국 문화에 대한 관심이 높을수록 한국 상품의 수출도 늘어나고 있습니다. 특히 한류 스타들이 화장품 모델을 하면서 화장품 수출이 크게 증가했습니다. 중국과 아시아 지역에서 한국 화장품의 인기가 아주 높습니다.","a":["한류는 수출에 아무런 영향이 없습니다.","한국 화장품은 아시아에서 인기가 없습니다.","한류 스타 모델 덕분에 화장품 수출이 늘었습니다.","자동차 수출은 점점 줄어들고 있습니다."],"c":"한류 스타 모델 덕분에 화장품 수출이 늘었습니다.","ex":"Ekspor produk kosmetik meningkat drastis karena bintang Hallyu menjadi model iklan produk tersebut.","romaji":"Hallyu yeolpung-gwa suchulyi gwangye-e daehan seolmyeong-euro manneun geoseun mueosimnikka?","ch":35},{"id":"l_35_05","q":"두 사람은 지금 무엇을 할 것입니까?","audio":"여: 투안 씨, 이제 곧 제가 좋아하는 음악 프로그램이 시작되는데 같이 볼래요? 남: 좋아요. 저도 한국 노래를 참 좋아하거든요. 여: 그럼 텔레비전을 켤게요. 같이 봐요. 남: 네, 맛있는 간식도 가져올게요.","a":["영화를 보러 갑니다.","쇼핑을 하러 갑니다.","텔레비전을 봅니다.","한국어 공부를 합니다."],"c":"텔레비전을 봅니다.","ex":"Mereka sepakat untuk menonton program musik di televisi bersama (텔레비전을... 같이 봐요).","romaji":"Du sarameun jigeum mueoseul hal geosimnikka?","ch":35},{"id":"l_36_01","q":"투안 씨는 무엇을 합니까?","audio":"반장님, 작업복 단추를 다 잠갔어요. 이제 아주 단정해 보이지요?","a":["넥타이를 맵니다","신발끈을 묶습니다","단추를 잠급니다","지퍼를 내립니다"],"c":"단추를 잠급니다","ex":"Tuan mengatakan bahwa ia telah mengancingkan (단추를 잠그다) semua kancing baju kerjanya agar terlihat rapi.","romaji":"Tuan ssineun mueoseul hamnikka? / Banjangnim, jagyeopbok danchureul da jamgat-seoyo. Ije aju danjeonghae boijiyo?","ch":36},{"id":"l_36_02","q":"리한 씨는 왜 불편해합니까?","audio":"새 작업복 지퍼를 목까지 올려야 해서 좀 답답해요. 그래도 안전을 위해서 참아야겠지요.","a":["옷이 너무 커서","지퍼를 올려야 해서","넥타이가 답답해서","작업복이 찢어져서"],"c":"지퍼를 올려야 해서","ex":"Rihan merasa tidak nyaman (답답하다/불편하다) karena harus menaikkan resleting sampai ke leher demi keamanan.","romaji":"Rihan ssineun wae bulpyeonhaehamnikka?","ch":36},{"id":"l_36_03","q":"여자는 남자에게 무엇을 제안합니까?","audio":"지훈 씨, 넥타이를 매니까 아주 단정해 보여요. 계속 그렇게 입으세요.","a":["단추를 푸는 것","넥타이를 매는 것","옷을 갈아입는 것","신발을 빌리는 것"],"c":"넥타이를 매는 것","ex":"Wanita tersebut memuji penampilan pria yang memakai dasi (넥타이를 매다) karena terlihat rapi dan menyarankannya untuk tetap seperti itu.","romaji":"Yeojaneun namja-ege mueoseul jeanhamnikka?","ch":36},{"id":"l_36_04","q":"대화 내용과 일치하는 것을 고르십시오.","audio":"여: 투안 씨, 왜 작업복 단추를 안 잠갔어요? 남: 너무 더워서 좀 풀었어요. 여: 더워도 작업복 단추를 풀면 안 돼요. 그러면 위험하니까 얼른 잠그세요. 남: 네, 알겠습니다. 지금 바로 단추를 잠글게요.","a":["남자는 지금 단추를 풀고 있습니다.","남자는 작업복을 입지 않았습니다.","여자는 남자에게 옷을 빌려줍니다.","남자는 단추를 잠글 것입니다."],"c":"남자는 단추를 잠글 것입니다.","ex":"Meskipun panas, Tuan diperintahkan untuk mengancingkan baju kerjanya karena berbahaya jika dilepas, dan Tuan setuju untuk segera mengancingkannya (잠글게요).","romaji":"Daehwa naeyong-gwa ilchihaneun geoseul goreusipsio.","ch":36},{"id":"l_36_05","q":"남자는 왜 작업복을 바꾸고 싶어 합니까?","audio":"남: 반장님, 일하다가 작업복이 찢어졌어요. 여: 그래요? 내가 새 걸로 신청해 놓을게요. 남: 그런데 제가 좀 살이 쪄서요. 이왕이면 조금 큰 사이즈로 주시면 좋겠습니다. 여: 알겠어요. 사이즈가 어떻게 되지요?","a":["작업복이 너무 커서","디자인이 마음에 안 들어서","작업복이 찢어지고 작아서","옷의 색깔이 이상해서"],"c":"작업복이 찢어지고 작아서","ex":"Pria tersebut ingin mengganti pakaian karena bajunya sobek (찢어지다) dan ia ingin ukuran yang lebih besar karena berat badannya bertambah.","romaji":"Namjaneun wae jagyeopbogeul bakkugo sipeo hamnikka?","ch":36},{"id":"l_37_01","q":"기숙사 시설물이 파손되면 어떻게 해야 합니까?","audio":"여러분, 기숙사 시설물이 파손되면 즉시 관리인에게 보고합시다. 그래야 빨리 고칠 수 있습니다.","a":["직접 고칩니다","그냥 둡니다","관리인에게 보고합니다","새 것을 삽니다"],"c":"관리인에게 보고합니다","ex":"Jika fasilitas asrama rusak (파손되다), penghuni diminta segera melapor kepada pengelola (관리인에게 보고하다).","romaji":"Gisuksa siseolmuri pason-doemyeon eotteoke haeya hamnikka?","ch":37},{"id":"l_37_02","q":"두 사람은 지금 무엇을 하려고 합니까?","audio":"가: 기숙사 대청소 언제 할까요? 나: 이번 주말에 쉬니까 이번 주에 합시다.","a":["요리를 합니다","대청소를 합니다","잠을 잡니다","외출을 합니다"],"c":"대청소를 합니다","ex":"Mereka sedang merencanakan waktu untuk melakukan pembersihan total (대청소) asrama.","romaji":"Du sarameun jigeum mueoseul haryeogo hamnikka?","ch":37},{"id":"l_37_03","q":"남자는 여자에게 무엇을 주의하라고 합니까?","audio":"냉방을 하는 동안에는 창문을 열면 안 돼요. 에너지가 낭비되니까 꼭 창문을 닫아 주세요.","a":["문을 열어 두는 것","에어컨을 끄는 것","창문을 닫는 것","불을 켜는 것"],"c":"창문을 닫는 것","ex":"Pria tersebut melarang membuka jendela selama pendinginan (냉방) berlangsung dan meminta agar jendela ditutup.","romaji":"Namjaneun yeoja-ege mueoseul juui-harago hamnikka?","ch":37},{"id":"l_37_04","q":"휴게실 사용 규칙에 대한 설명으로 맞는 것은 무엇입니까?","audio":"관리인: 휴게실에 있는 동안 전기난로를 잘 사용하고 나갈 때는 꼭 스위치를 끄세요. 그리고 플러그도 뽑아 놓으세요. 지난번에는 아무도 없는데 난로가 켜 있어서 깜짝 놀랐어요. 리한: 네, 알겠어요. 제가 신경 쓸게요.","a":["나갈 때 난로를 켜 둡니다.","플러그를 항상 꽂아 둡니다.","나갈 때 플러그를 뽑아야 합니다.","난로 스위치를 켜 놓아야 합니다."],"c":"나갈 때 플러그를 뽑아야 합니다.","ex":"Pengelola asrama menginstruksikan agar mematikan sakelar dan mencabut steker (플러그를 뽑다) pemanas listrik saat meninggalkan ruang istirahat.","romaji":"Hyugesil sayong gyuchige daehan seolmyeong-euro manneun geoseun mueosimnikka?","ch":37},{"id":"l_37_05","q":"기숙사 생활 규칙에 대한 내용과 다른 것은 무엇입니까?","audio":"안내 말씀 드립니다. 요즘 많은 사람이 규칙을 안 지킵니다. 첫째, 세탁실을 사용한 후에는 잘 정리합시다. 둘째, 밤에는 큰 소리로 떠들지 맙시다. 셋째, 기숙사에 외부인을 데리고 오지 마세요. 마지막으로 외출할 때는 출입문을 꼭 닫읍시다.","a":["밤에는 조용히 해야 합니다.","친구를 데려와도 됩니다.","세탁실은 사용 후 정리해야 합니다.","나갈 때 문을 닫아야 합니다."],"c":"친구를 데려와도 됩니다.","ex":"Peraturan menyatakan dilarang membawa orang luar/teman (외부인을 데리고 오지 마세요), sehingga opsi B salah.","romaji":"Gisuksa saenghwal gyuchige daehan naeyong-gwa dareun geoseun mueosimnikka?","ch":37},{"id":"l_38_01","q":"이 회사의 분위기는 어떻습니까?","audio":"우리 회사는 분위기가 아주 자유로운 편이에요. 그래서 일할 맛이 나요.","a":["규율이 엄격합니다","분위기가 자유롭습니다","상사가 무섭습니다","동료와 사이가 나쁩니다"],"c":"분위기가 자유롭습니다","ex":"Pembicara menyatakan bahwa suasana kantornya sangat bebas (자유롭다).","romaji":"I hoesayi bun-wigineun eotteoseumnikka?","ch":38},{"id":"l_38_02","q":"투안 씨는 왜 기분이 좋습니까?","audio":"바루 씨하고 오해가 풀렸어요. 서로 사과하고 화해해서 정말 기분이 좋아요.","a":["보너스를 받아서","고향에 가게 되어서","동료와 화해해서","일이 일찍 끝나서"],"c":"동료와 화해해서","ex":"Tuan merasa senang karena salah pahamnya dengan Baru telah selesai dan mereka sudah berbaikan (화해하다).","romaji":"Tuan ssineun wae gibuni jouseumnikka?","ch":38},{"id":"l_38_03","q":"상사를 부를 때 어떻게 해야 합니까?","audio":"회사에서 상사를 부를 때는 직책 뒤에 '님'을 꼭 붙여서 부르세요.","a":["이름을 부릅니다","반말을 합니다","직책에 '님'을 붙입니다","'형'이라고 부릅니다"],"c":"직책에 '님'을 붙입니다","ex":"Etika memanggil atasan adalah dengan menambahkan akhiran '-nim' pada jabatannya.","romaji":"Sangsareul bureul ttae eotteoke haeya hamnikka?","ch":38},{"id":"l_38_04","q":"대화 내용과 일치하는 것을 고르십시오.","audio":"여: 아직도 수미 씨에게 화가 났어요? 남: 아니요, 벌써 화해했어요. 제가 먼저 미안하다고 했거든요. 여: 정말 잘하셨어요. 동료끼리 서로 배려하면서 지내야 일할 때도 즐겁잖아요. 남: 맞아요. 이제는 안 싸울 거예요.","a":["남자는 아직 수미 씨에게 화가 났습니다.","수미 씨가 남자에게 먼저 사과했습니다.","남자가 수미 씨에게 먼저 사과했습니다.","두 사람은 아직 화해하지 않았습니다."],"c":"남자가 수미 씨에게 먼저 사과했습니다.","ex":"Pria tersebut mengatakan bahwa ia sudah berbaikan dan dialah yang meminta maaf (미안하다고 하다) duluan.","romaji":"Daehwa naeyong-gwa ilchihaneun geoseul goreusipsio.","ch":38},{"id":"l_38_05","q":"좋은 직장 분위기를 만드는 방법으로 알맞지 않은 것은 무엇입니까?","audio":"좋은 직장 분위기를 만들기 위해서는 모든 사람의 노력이 필요합니다. 직장에서는 서로에게 웃는 얼굴로 이야기하는 게 좋습니다. 그리고 서로를 배려하는 마음을 갖는다면 화내는 일이 없어질 것입니다. 상대방의 마음을 한 번 더 생각합시다.","a":["웃는 얼굴로 대화하기","서로 배려하기","상대방의 마음 생각하기","자신의 생각만 고집하기"],"c":"자신의 생각만 고집하기","ex":"Teks menyarankan untuk tersenyum, bertenggang rasa, dan memikirkan perasaan orang lain. Bersikap keras kepala dengan pikiran sendiri (고집하다) tidak disebutkan sebagai cara yang baik.","romaji":"Joeun jikjang bun-wigireul mandeuneun bangbeop-euro almaji anneun geoseun mueosimnikka?","ch":38},{"id":"l_39_01","q":"오늘 회식 메뉴는 무엇입니까?","audio":"오늘 저녁에 회식을 하자고 해요. 이번에도 삼겹살집으로 가기로 했어요.","a":["치킨","삼겹살","갈비탕","비빔밥"],"c":"삼겹살","ex":"Menu makan bersama (회식) kali ini adalah Samgyeopsal.","romaji":"Oneul hoesik menyuneun mueoseul hamnikka?","ch":39},{"id":"l_39_02","q":"2차는 어디로 가기로 했습니까?","audio":"1차는 삼겹살을 먹고, 2차는 시원한 맥주에 치킨을 먹으러 갑시다.","a":["노래방","치킨집","회사","집"],"c":"치킨집","ex":"Setelah ronde pertama (1차), mereka berencana pergi makan ayam (치킨) untuk ronde kedua (2차).","romaji":"Ichaneun eodiro gagiro haesseumnikka?","ch":39},{"id":"l_39_03","q":"여자는 누구를 소개하고 있습니까?","audio":"여기 좀 보세요. 다음 달부터 같이 일하게 된 타타 씨입니다.","a":["사장님","반장님","새 직원","관리인"],"c":"새 직원","ex":"Wanita (Kepala Pabrik) memperkenalkan Tata sebagai karyawan baru (새 직원) yang mulai bekerja bulan depan.","romaji":"Yeojaneun nugureul sogaehago isseumnikka?","ch":39},{"id":"l_39_04","q":"대화 내용과 일치하는 것을 고르십시오.","audio":"남: 여러분, 이번 주 금요일에 회식하는 거 잊지 않았지요? 한 명도 빠짐없이 참석하세요. 여: 부장님, 모니카 씨는 가족들이 고향에서 와서 못 온대요. 남: 아, 그래요? 그럼 어쩔 수 없지요. 나머지 분들은 다 오세요.","a":["모든 직원이 회식에 참석합니다.","회식은 목요일에 합니다.","모니카 씨는 회식에 못 옵니다.","부장님은 회식을 취소했습니다."],"c":"모니카 씨는 회식에 못 옵니다.","ex":"Monika tidak bisa hadir karena keluarganya datang dari kampung halaman, sehingga tidak semua orang hadir.","romaji":"Daehwa naeyong-gwa ilchihaneun geoseul goreusipsio.","ch":39},{"id":"l_39_05","q":"한국의 회식 문화에 대한 설명으로 맞는 것은 무엇입니까?","audio":"한국에서는 회식 때 술을 마시는 경우가 많습니다. 상사가 술을 따라 주면 두 손으로 받아야 합니다. 그리고 술을 마실 때는 고개를 상사 반대쪽으로 돌리고 마시는 것이 예의입니다. 요즘은 술 대신 공연을 보기도 합니다.","a":["술을 한 손으로 받아도 됩니다.","상사 앞에서 정면으로 마십니다.","상사가 주는 술은 두 손으로 받습니다.","회식 때는 항상 술만 마십니다."],"c":"상사가 주는 술은 두 손으로 받습니다.","ex":"Etika minum alkohol dengan atasan adalah menerima gelas dengan dua tangan (두 손으로 받다) dan memalingkan wajah saat meminumnya.","romaji":"Hangukui hoesik munhwa-e daehan seolmyeong-euro manneun geoseun mueosimnikka?","ch":39},{"id":"l_40_01","q":"성희롱을 당했을 때 어떻게 해야 합니까?","audio":"성희롱을 당했다면 정확하게 자신의 거부 의사를 표현하는 것이 아주 중요합니다.","a":["그냥 참습니다","거부 의사를 표현합니다","모르는 척합니다","화를 내고 싸웁니다"],"c":"거부 의사를 표현합니다","ex":"Hal yang terpenting saat mengalami pelecehan adalah mengungkapkan penolakan secara jelas (거부 의사를 표현하다).","romaji":"Seong-huirong-eul dang-haesseul ttae eotteoke haeya hamnikka?","ch":40},{"id":"l_40_02","q":"여자는 왜 상담센터에 전화했습니까?","audio":"여보세요? 거기 상담센터지요? 성희롱 상담을 받고 싶은데 예약을 어떻게 해야 돼요?","a":["직업을 구하려고","상담 예약을 하려고","친구를 찾으려고","물건을 사려고"],"c":"상담 예약을 하려고","ex":"Wanita tersebut menelepon untuk menanyakan cara membuat reservasi konsultasi (상담 예약).","romaji":"Yeojaneun wae sangdam-senteo-e jeonhwahaesseumnikka?","ch":40},{"id":"l_40_03","q":"남자는 무엇을 조심하겠다고 했습니까?","audio":"미안해요. 그런 의도는 아니었는데, 앞으로는 성적 농담을 정말 조심할게요.","a":["늦잠 자는 것","일하는 방법","성적 농담","음식 먹는 것"],"c":"성적 농담","ex":"Pria tersebut meminta maaf dan berjanji akan berhati-hati dengan candaan bersifat seksual (성적 농담) di masa depan.","romaji":"Namjaneun mueoseul josim-hagetdago haesseumnikka?","ch":40},{"id":"l_40_04","q":"성희롱 증거 확보에 대한 설명으로 맞는 것은 무엇입니까?","audio":"직장 내에서 성희롱이 발생했다면 사건을 정확하게 기록해 두어야 합니다. 사진을 찍거나 녹음을 해서 증거를 확보하는 게 좋습니다. 그리고 언제, 어디에서, 누가 그런 행동을 했는지 날짜와 시간을 자세히 써 놓아야 나중에 도움이 됩니다.","a":["증거는 필요 없습니다.","사진이나 녹음이 증거가 될 수 있습니다.","날짜와 장소는 쓰지 않아도 됩니다.","기분이 나빠도 기록하지 않습니다."],"c":"사진이나 녹음이 증거가 될 수 있습니다.","ex":"Foto atau rekaman (사진이나 녹음) disebutkan sebagai cara untuk mengamankan bukti (증거 확보).","romaji":"Seong-huirong jeung-geo hwakbo-e daehan seolmyeong-euro manneun geoseun mueosimnikka?","ch":40},{"id":"l_40_05","q":"대화 내용으로 알 수 있는 것은 무엇입니까?","audio":"여: 수미 씨가 왜 기분이 안 좋아 보여요? 남: 아까 지훈 씨가 수미 씨 어깨를 만지면서 장난을 쳤거든요. 여: 그건 성희롱이 될 수 있는 행동이잖아요. 친한 사이라도 신체 접촉은 조심해야 해요. 남: 맞아요. 지훈 씨가 수미 씨에게 빨리 사과해야 할 것 같아요.","a":["수미 씨는 지금 기분이 아주 좋습니다.","지훈 씨는 수미 씨에게 사과했습니다.","신체 접촉은 성희롱이 될 수 있습니다.","두 사람은 같이 운동을 하고 있습니다."],"c":"신체 접촉은 성희롱이 될 수 있습니다.","ex":"Kontak fisik (신체 접촉) seperti menyentuh bahu dapat dianggap sebagai pelecehan seksual meskipun dilakukan sebagai candaan.","romaji":"Daehwa naeyong-euro al su itneun geoseun mueosimnikka?","ch":40},{"id":"l_41_01","q":"바루 씨는 지금 무엇을 찾고 있습니까?","audio":"반장님, 망치 못 봤어요? 아무리 찾아도 없네요. 공구함에도 없어서 못을 못 박고 있어요.","a":["나사못","망치","펜치","니퍼"],"c":"망치","ex":"Baru sedang mencari palu (망치) untuk memaku tetapi tidak menemukannya di kotak perkakas.","romaji":"Baru ssineun jigeum mueoseul chatgo isseumnikka? / Banjangnim, mangchi mot bwasseoyo? Amuri chajado eomneyo. Gongguhamedo eopseoseo moseul mot bakgo isseoyo.","ch":41},{"id":"l_41_02","q":"여자는 남자에게 무엇을 가져다 달라고 했습니까?","audio":"투안 씨, 괜찮으면 리한 씨한테 용접봉 좀 가져다주세요. 아까부터 작업장에서 찾고 있었어요.","a":["전기 절단기","스패너","용접봉","전기 드릴"],"c":"용접봉","ex":"Wanita tersebut meminta Tuan untuk membawakan batang las (용접봉) kepada Rihan.","romaji":"Yeojaneun namja-ege mueoseul gajyeoda dallago haesseumnikka?","ch":41},{"id":"l_41_03","q":"남자는 지금 무엇을 하고 있습니까?","audio":"지금 전기 용접기로 붙이는 작업을 하고 있어요. 불꽃이 튀니까 조심하세요.","a":["구멍을 뚫고 있습니다","물건을 운반하고 있습니다","용접을 하고 있습니다","나무를 자르고 있습니다"],"c":"용접을 하고 있습니다","ex":"Pria tersebut sedang melakukan pekerjaan mengelas (용접) menggunakan mesin las listrik.","romaji":"Namjaneun jigeum mueoseul hago isseumnikka?","ch":41},{"id":"l_41_04","q":"여자가 작업을 구경하기 위해 가장 먼저 해야 할 일은 무엇입니까?","audio":"여: 반장님, 절단기로 절단하는 거 구경해도 돼요? 남: 위험해서 안 돼요. 여: 반장님처럼 보호구를 쓰고 볼게요. 남: 좋아요. 그러면 보호구를 쓰고 오세요.","a":["절단기를 가져옵니다.","보호구를 착용합니다.","반장님을 부릅니다.","작업을 시작합니다."],"c":"보호구를 착용합니다.","ex":"Mandor mengizinkan wanita tersebut melihat proses pemotongan asalkan ia memakai alat pelindung diri (보호구) terlebih dahulu.","romaji":"Yeojaga jagyeobeul gugyeonghagi wihae gajang meonjeo haeya hal ireun mueosimnikka?","ch":41},{"id":"l_41_05","q":"남자가 오늘 한 작업은 무엇입니까?","audio":"저는 가구 공장에서 일합니다. 요즘은 책상을 만드는데 어제는 나무를 잘랐고 오늘은 구멍을 뚫는 작업을 했습니다. 전기 드릴을 사용하면 아주 쉽게 할 수 있습니다.","a":["나무를 잘랐습니다.","도구를 정리했습니다.","구멍을 뚫었습니다.","못을 박았습니다."],"c":"구멍을 뚫었습니다.","ex":"Meskipun kemarin ia memotong kayu, pembicara menyatakan bahwa pekerjaan yang dilakukan \"hari ini\" adalah melubangi kayu (구멍을 뚫는 작업) menggunakan bor listrik.","romaji":"Namjaga oneul han jagyeobeun mueosimnikka?","ch":41},{"id":"l_42_01","q":"이 기계는 어떻게 작동하기 시작합니까?","audio":"손잡이에 있는 안전 스위치를 누르세요. 그 다음에 전원 스위치를 올리면 작동하기 시작합니다.","a":["스위치를 내립니다","전원 스위치를 올립니다","손잡이를 돌립니다","줄을 겁니다"],"c":"전원 스위치를 올립니다","ex":"Mesin akan mulai beroperasi jika saklar power dinaikkan (전원 스위치를 올리다) setelah menekan tombol keamanan.","romaji":"I gigyeneun eotteoke jakdonghagi sijakhamnikka?","ch":42},{"id":"l_42_02","q":"여자는 남자에게 무엇을 물어보았습니까?","audio":"민수 씨, 이 기계 어떻게 사용하는지 알아요? 오늘 처음이라서 잘 모르겠어요.","a":["기계의 가격","기계 사용 방법","기계의 종류","기계 수리 날짜"],"c":"기계 사용 방법","ex":"Wanita tersebut bertanya apakah pria itu tahu cara menggunakan (사용하는지 알다) mesin tersebut karena ia baru pertama kali mengoperasikannya.","romaji":"Yeojaneun namja-ege mueoseul mureobwasseumnikka?","ch":42},{"id":"l_42_03","q":"남자는 지금 무슨 일을 하고 있습니까?","audio":"저는 냄비 만드는 곳에서 일해요. 아직 기계 작동법을 몰라서 주로 물건을 옮기는 일을 해요.","a":["냄비를 만듭니다","기계를 고칩니다","물건을 옮깁니다","전구를 끼웁니다"],"c":"물건을 옮깁니다","ex":"Pria tersebut (Minsu) belum bisa mengoperasikan mesin, jadi pekerjaannya saat ini adalah memindahkan barang (물건을 옮기다).","romaji":"Namjaneun jigeum museun ireul hago isseumnikka?","ch":42},{"id":"l_42_04","q":"작업장 안전 수칙에 대한 설명으로 맞는 것은 무엇입니까?","audio":"안내 말씀 드립니다. 어제 작업장 청소를 해서 바닥이 많이 미끄럽습니다. 넘어지지 않게 조심하세요. 그리고 기계에 물이 들어가지 않도록 주의해 주시기 바랍니다.","a":["바닥에 물을 뿌려야 합니다.","기계에 물이 들어가지 않게 합니다.","기계 작동법을 가르쳐 줍니다.","기계를 고치러 갑니다."],"c":"기계에 물이 들어가지 않게 합니다.","ex":"Pengumuman mengingatkan agar berhati-hati karena lantai licin dan meminta agar air tidak masuk ke dalam mesin (기계에 물이 들어가지 않도록).","romaji":"Jagyeopjang anjeon suchige daehan seolmyeong-euro manneun geoseun mueosimnikka?","ch":42},{"id":"l_42_05","q":"인디카 씨의 오늘 오후 작업은 무엇입니까?","audio":"오전에는 골판지 자르는 작업을 다 끝냈습니다. 그래서 오후부터는 상자를 접고 붙이는 작업을 하고 있습니다. 6시까지는 주문 받은 상자를 모두 완성할 수 있을 것 같습니다.","a":["골판지를 자릅니다.","골판지를 주문합니다.","상자를 접고 붙입니다.","물건을 옮깁니다."],"c":"상자를 접고 붙입니다.","ex":"Indica sudah selesai memotong di pagi hari, dan pada sore hari ia melakukan pekerjaan melipat dan menempel (접고 붙이는 작업) kotak.","romaji":"Indika ssiyi oneul ohu jagyeobeun mueosimnikka?","ch":42},{"id":"l_43_01","q":"남자의 팀은 오늘 가장 먼저 무슨 일을 합니까?","audio":"우리 팀은 오늘 철근을 조립하기 전에 여기 있는 철근들을 3층으로 옮겨 놓을 겁니다.","a":["거푸집 설치","콘크리트 타설","철근 운반","땅 파기"],"c":"철근 운반","ex":"Tim tersebut akan memindahkan kawat besi (철근을 옮겨 놓다) ke lantai 3 sebagai pekerjaan pertama hari ini.","romaji":"Namjayi tim-eun oneul gajang meonjeo museun ireul hamnikka?","ch":43},{"id":"l_43_02","q":"모니카 씨는 물건을 어떻게 포장했습니까?","audio":"내일 납품할 물건들 포장 끝났어요? 네, 크기별로 분류해서 따로 포장해 놓았어요.","a":["한 상자에 모두 담았습니다","크기별로 분류해서 포장했습니다","아직 시작하지 않았습니다","무게를 재지 않고 담았습니다"],"c":"크기별로 분류해서 포장했습니다","ex":"Monika sudah mengemas barang dengan memisahkannya berdasarkan ukuran (크기별로 분류해서 따로 포장).","romaji":"Monica ssineun mulgeoneul eotteoke pojang-haesseumnikka?","ch":43},{"id":"l_43_03","q":"남자는 대화 후에 무엇을 하겠습니까?","audio":"바닥에 기름이 흘러서 너무 위험해요. 네, 반장님. 제가 빨리 바닥을 닦고 창고에 다녀올게요.","a":["창고에 먼저 갑니다","페인트를 칠합니다","바닥을 닦습니다","물건을 분류합니다"],"c":"바닥을 닦습니다","ex":"Pria tersebut akan segera mengepel lantai (바닥을 닦다) karena ada tumpahan minyak yang berbahaya.","romaji":"Namjaneun daehwa hue mueoseul hagetseumnikka?","ch":43},{"id":"l_43_04","q":"들은 내용과 일치하지 않는 것을 고르십시오.","audio":"여러분, 지금부터 오늘 작업을 알려 드립니다. 오늘은 거푸집을 설치하고 철근을 조립합니다. 아딧 씨 팀이 철근을 다 옮기면 바로 조립 작업을 시작하세요. 작업이 끝나면 반드시 반장에게 보고해야 합니다.","a":["철근을 옮기는 일이 있습니다.","거푸집을 설치하는 일이 있습니다.","작업 후에 보고를 안 해도 됩니다.","철근 조립 작업을 할 예정입니다."],"c":"작업 후에 보고를 안 해도 됩니다.","ex":"Audio menyatakan bahwa setelah selesai bekerja harus melapor (보고해야 합니다), sehingga pernyataan bahwa tidak perlu melapor adalah salah.","romaji":"Deureun naeyong-gwa ilchihaji anneun geoseul goreusipsio.","ch":43},{"id":"l_43_05","q":"앞으로 해야 할 작업이 아닌 것은 무엇입니까?","audio":"이제 거푸집 설치 작업이 끝났습니다. 지금부터는 철근 조립 작업과 콘크리트 타설 작업을 시작하겠습니다. 철근 조립이 끝나면 콘크리트를 확인하고 바로 타설하세요.","a":["철근 조립","거푸집 설치","콘크리트 확인","콘크리트 타설"],"c":"거푸집 설치","ex":"Karena pemasangan cetakan (거푸집 설치) sudah selesai (끝났습니다), maka itu bukan lagi pekerjaan yang akan dilakukan selanjutnya.","romaji":"Apeuro haeya hal jagyeobi anin geoseun mueosimnikka?","ch":43},{"id":"l_44_01","q":"작업장에서 왜 페인트 냄새가 많이 납니까?","audio":"작업장에 페인트 냄새가 아주 심하네요. 어제 늦게까지 페인트 작업을 했거든요.","a":["지금 작업 중이라서","환풍기가 고장 나서","어제 페인트 작업을 해서","페인트를 쏟아서"],"c":"어제 페인트 작업을 해서","ex":"Bau cat sangat menyengat karena mereka melakukan pekerjaan pengecatan (페인트 작업을 했거든요) sampai larut malam kemarin.","romaji":"Jagyeopjang-eseo wae peinteu naemsaega mani namnikka?","ch":44},{"id":"l_44_02","q":"여자는 지금 무엇을 하고 있습니까?","audio":"작업장에 냄새가 너무 많이 나요. 그래서 지금 창문을 열고 환기하고 있어요.","a":["페인트를 칠합니다","청소를 합니다","환기를 합니다","도구를 정리합니다"],"c":"환기를 합니다","ex":"Wanita tersebut sedang melakukan ventilasi (환기하다) dengan membuka jendela karena bau.","romaji":"Yeojaneun jigeum mueoseul hago isseumnikka?","ch":44},{"id":"l_44_03","q":"남자는 리한 씨에게 무엇을 제안했습니까?","audio":"리한 씨, 주말에 우리 집에서 집들이를 하는데 올 수 있어요? 저녁 7시까지 오면 돼요.","a":["같이 등산하는 것","집들이에 오는 것","페인트 작업을 돕는 것","공구를 정리하는 것"],"c":"집들이에 오는 것","ex":"Pria tersebut mengundang Rihan untuk datang ke acara selamatan rumah baru (집들이) pada akhir pekan.","romaji":"Namjaneun Rihan ssiege mueoseul jean-haesseumnikka?","ch":44},{"id":"l_44_04","q":"남자가 말한 정리 정돈의 효과가 아닌 것은 무엇입니까?","audio":"작업장 정리를 잘하면 안전사고를 예방할 수 있습니다. 그리고 물건의 낭비를 줄이고 제품의 품질을 높일 수 있습니다. 마지막으로 기계를 오랫동안 사용할 수 있게 됩니다.","a":["제품의 품질이 낮아집니다.","안전사고를 예방합니다.","물건의 낭비를 줄입니다.","기계를 오래 사용합니다."],"c":"제품의 품질이 낮아집니다.","ex":"Penataan yang baik meningkatkan kualitas produk (품질을 높일 수 있습니다), bukan menurunkannya.","romaji":"Namjaga malhan jeongri jeongdonui hyogwaga anin geoseun mueosimnikka?","ch":44},{"id":"l_44_05","q":"사장님은 왜 시청에 가셨습니까?","audio":"사장님 지금 계세요? 아니요, 지금 시청에 가셨어요. 폐수 처리 방법에 대한 설명을 들으러 가셨거든요. 요즘 폐수 처리 문제가 좀 복잡해졌잖아요.","a":["페인트를 사러","시청 청소를 하러","교육을 받으러","친구를 만나러"],"c":"교육을 받으러","ex":"Direktur pergi ke Balai Kota untuk mendengarkan penjelasan/pelatihan (설명을 들으러/교육) mengenai cara pembuangan limbah.","romaji":"Sajangnim-eun wae sicheong-e gasyeosseumnikka?","ch":44},{"id":"l_45_01","q":"리리 씨는 왜 창고에 가려고 합니까?","audio":"오늘 일할 밭은 너무 딱딱해서 호미로 하기 힘들어요. 창고에 가서 괭이를 좀 가져오세요.","a":["호미를 고치려고","괭이를 가져오려고","씨앗을 뿌리려고","비료를 챙기려고"],"c":"괭이를 가져오려고","ex":"Riri diminta ke gudang untuk mengambil cangkul (괭이) karena tanahnya keras.","romaji":"Riri ssineun wae changgo-e garyeogo hamnikka?","ch":45},{"id":"l_45_02","q":"모종은 언제 심어야 합니까?","audio":"비료를 먼저 뿌리고 일주일쯤 지난 후에 모종을 심어야 해요. 그래야 잘 자라거든요.","a":["오늘 바로","비료를 뿌리기 전에","비료를 뿌리고 일주일 후에","한 달 후에"],"c":"비료를 뿌리고 일주일 후에","ex":"Benih harus ditanam sekitar satu minggu setelah menebar pupuk (비료를 뿌리고 일주일쯤 지난 후에).","romaji":"Mojong-eun eonje sim-eoya hamnikka?","ch":45},{"id":"l_45_03","q":"남자는 내일 오후에 무슨 일을 할 것입니까?","audio":"오전에는 농약을 치고, 오후에는 고구마 밭에 가서 물을 좀 줄게요.","a":["농약을 칩니다","잡초를 뽑습니다","물을 줍니다","거름을 줍니다"],"c":"물을 줍니다","ex":"Pria tersebut berencana menyemprot pestisida di pagi hari dan memberi air (물을 주다) di sore hari.","romaji":"Namjaneun naeil ohu-e museun ireul hal geosimnikka?","ch":45},{"id":"l_45_04","q":"여자가 남자에게 주의하라고 말한 내용은 무엇입니까?","audio":"오늘 괭이로 고구마를 캘 거예요. 그런데 괭이를 사용할 때는 고구마에 상처가 나지 않게 조심해야 돼요. 알겠지요?","a":["괭이를 잃어버리지 않게 합니다.","밭을 너무 깊게 파지 않습니다.","고구마에 상처가 나지 않게 합니다.","손을 다치지 않게 장갑을 낍니다."],"c":"고구마에 상처가 나지 않게 합니다.","ex":"Ibu pemilik usaha mengingatkan agar berhati-hati supaya tidak melukai ubi jalar (고구마에 상처가 나지 않게 조심) saat menggunakan cangkul.","romaji":"Yeojaga namja-ege juui-harago malhan naeyong-eun mueosimnikka?","ch":45},{"id":"l_45_05","q":"토마토 모종을 심기 위한 순서로 맞는 것은 무엇입니까?","audio":"토마토를 심으려면 먼저 밭에 비료를 뿌리세요. 그리고 일주일 정도 기다리세요. 그 후에 모종을 심고 물을 주면 됩니다.","a":["비료 뿌리기 - 모종 심기 - 물 주기","물 주기 - 비료 뿌리기 - 모종 심기","모종 심기 - 물 주기 - 비료 뿌리기","비료 뿌리기 - 물 주기 - 모종 심기"],"c":"비료 뿌리기 - 모종 심기 - 물 주기","ex":"Urutannya adalah menebar pupuk (비료 뿌리기), menunggu seminggu, menanam benih (모종 심기), lalu memberi air (물 주기).","romaji":"Tomato mojong-eul simgi wihaan sunseoro manneun geoseun mueosimnikka?","ch":45},{"id":"l_46_01","q":"여자는 남자에게 무엇을 하라고 했습니까?","audio":"벌써 계란 선별을 다 했어요? 수고했어요. 그럼 이제 저쪽 닭장에 가서 사료 좀 주세요.","a":["계란을 선별합니다","닭장에 사료를 줍니다","축사를 청소합니다","소 먹이를 준비합니다"],"c":"닭장에 사료를 줍니다","ex":"Wanita tersebut memerintahkan pria untuk memberi pakan (사료 좀 주세요) di kandang ayam (닭장).","romaji":"Yeojaneun namjaege mueoseul harago haesseumnikka? / Beolsseo gyeran seonbyeoreul da haesseoyo? Sugohaesseoyo. Geureom ije jeojjok dakjyange gaseo saryo jom juseyo.","ch":46},{"id":"l_46_02","q":"소의 상태가 지금 어떠합니까?","audio":"지난번에 바꾼 사료가 소한테 잘 안 맞는 것 같아. 오늘은 배까지 불룩해지고 가스도 많이 찼어.","a":["기분이 아주 좋습니다","배가 부풀어 올랐습니다","사료를 아주 잘 먹습니다","운동을 해서 날씬합니다"],"c":"배가 부풀어 올랐습니다","ex":"Perut sapi bengkak (배까지 불룩해지고) dan penuh gas karena pakan yang tidak cocok.","romaji":"Soyi sangtaega jigeum eotteohamnikka?","ch":46},{"id":"l_46_03","q":"남자는 사료를 어디에서 가져와야 합니까?","audio":"축사에 가서 소 먹이를 주도록 하세요. 네, 알겠습니다. 비닐하우스 옆에 있는 창고에 가서 가져올게요.","a":["사무실","비닐하우스 안","비닐하우스 옆 창고","농협중앙회"],"c":"비닐하우스 옆 창고","ex":"Pria tersebut mengatakan akan mengambil pakan di gudang (창고) yang terletak di sebelah rumah kaca (비닐하우스 옆).","romaji":"Namjaneun saryoreul eodieseo gajyeowaya hamnikka?","ch":46},{"id":"l_46_04","q":"두 사람이 화가 난 이유는 무엇입니까?","audio":"가: 그물 좀 미리미리 정리해 놓으라니까 또 그냥 이렇게 뒀네. 나: 몇 번이나 말했는데 또 그런 거야? 카림 형, 이번엔 마문 씨 불러서 단단히 혼을 좀 내. 가: 한 번 쓴 그물은 다 엉켜서 다시 쓰기 어려우니까 꼭 풀어 놓으라고 했는데. 이것 때문에 오늘도 작업을 제때 못 하게 됐잖아.","a":["그물이 너무 비싸서","마문 씨가 다쳐서","그물을 정리하지 않아서","물고기가 잡히지 않아서"],"c":"그물을 정리하지 않아서","ex":"Mereka marah karena jaring tidak dirapikan (그물을 정리해 놓으라니까 그냥 뒀네), sehingga pekerjaan terhambat karena jaring yang kusut.","romaji":"Du sarami hwaga nan iyuneun mueosimnikka?","ch":46},{"id":"l_46_05","q":"대화 내용과 다른 것을 고르십시오.","audio":"여: 어제 작업할 때 보니까 양망기가 잘 돌아가지 않던데……. 남: 안 그래도 수리 맡겼으니까 곧 고칠 거예요. 그리고 오늘은 멀리 안 나갈 거니까 괜찮아요. 그물 엉킨 게 있는지만 좀 확인해 봅시다. 여: 네, 그럼 제가 가서 그물을 먼저 확인하도록 할게요.","a":["양망기는 수리를 맡겼습니다.","오늘은 바다 멀리 나갈 겁니다.","여자는 그물을 확인하러 갑니다.","어제 양망기 상태가 안 좋았습니다."],"c":"오늘은 바다 멀리 나갈 겁니다.","ex":"Pria tersebut mengatakan hari ini tidak akan berlayar jauh (오늘은 멀리 안 나갈 거니까), sehingga opsi B salah.","romaji":"Daehwa naeyonggwa dareun geoseul goreusipsio.","ch":46},{"id":"l_47_01","q":"칸 씨는 지금 무엇을 하고 있습니까?","audio":"오늘 출고할 상품은 모두 준비됐지요? 네, 이쪽에 있는 물건들이 오늘 나갈 상품입니다. 그리고 재고는 여기에 기록해 두었고요.","a":["상자를 만듭니다","상품 출고를 준비합니다","창고를 청소합니다","기계를 고치고 있습니다"],"c":"상품 출고를 준비합니다","ex":"Khan sedang menyiapkan barang yang akan keluar dari gudang hari ini (오늘 출고할 상품).","romaji":"Khan ssineun jigeum mueoseul hago isseumnikka?","ch":47},{"id":"l_47_02","q":"가구를 만들 때 가장 먼저 해야 할 일은 무엇입니까?","audio":"가구를 만들 때 제일 먼저 해야 하는 일은 바로 원목을 재단하는 일입니다. 용도에 맞게 정확한 크기로 재는 것이 중요합니다.","a":["조립하기","사포질하기","원목 재단하기","도색 작업하기"],"c":"원목 재단하기","ex":"Langkah pertama dalam membuat mebel adalah memotong/mengukur bahan baku kayu (원목을 재단하는 일).","romaji":"Gagureul mandeul ttae gajang meonjeo haeya hal ireun mueosimnikka?","ch":47},{"id":"l_47_03","q":"남자는 왜 기분이 좋지 않습니까?","audio":"지훈 씨, 어쩌죠? 원목을 잘못 잘랐어요. 재단부터 다시 하려면 시간이 많이 걸릴 텐데 걱정이에요.","a":["일이 너무 쉬워서","원목을 잘못 잘라서","배가 고파서","도구가 없어서"],"c":"원목을 잘못 잘라서","ex":"Pria tersebut merasa khawatir/tidak tenang karena salah memotong kayu (원목을 잘못 잘랐어요).","romaji":"Namjaneun wae gibuni joji anseumnikka?","ch":47},{"id":"l_47_04","q":"여자의 근무 시간에 대한 설명으로 맞는 것을 고르십시오.","audio":"남: 가구 공장에서 무슨 일을 해야 해요? 여: 가구 조립을 하게 될 텐데 날마다 일이 있어. 남: 일이 몇 시에 끝나요? 여: 보통 저녁 7시에 끝나. 하지만 가끔 야간 근무도 해야 해.","a":["매일 밤 10시에 퇴근합니다.","조립 일은 일주일에 한 번 합니다.","보통 저녁 7시에 일이 끝납니다.","야간 근무는 절대로 하지 않습니다."],"c":"보통 저녁 7시에 일이 끝납니다.","ex":"Pekerjaan biasanya selesai pukul 7 malam (저녁 7시에 끝나), meskipun kadang ada kerja lembur malam.","romaji":"Yeojayi geunmu sigane daehan seolmyeong-euro manneun geoseul goreusipsio.","ch":47},{"id":"l_47_05","q":"들은 내용과 일치하지 않는 것을 고르십시오.","audio":"창고 관리는 재고를 파악하는 것이 매우 중요합니다. 물건을 입고하거나 출고할 때는 반드시 기록해야 합니다. 특히 식품을 보관할 때는 알맞은 온도를 유지하는 것이 가장 중요합니다.","a":["재고를 파악하는 것이 중요합니다.","물건을 낼 때는 기록하지 않아도 됩니다.","식품 창고는 온도를 유지해야 합니다.","창고 관리에 신경을 써야 합니다."],"c":"물건을 낼 때는 기록하지 않아도 됩니다.","ex":"Disebutkan bahwa saat memasukkan atau mengeluarkan barang harus dicatat (반드시 기록해야 합니다), sehingga opsi B salah.","romaji":"Deureun naeyonggwa ilchihaji anneun geoseul goreusipsio.","ch":47},{"id":"l_48_01","q":"투안 씨는 왜 \"큰일 날 뻔했다\"고 말했습니까?","audio":"투안 씨, 괜찮아요? 네. 모서리 맞추려고 한 건데 큰일 날 뻔했네요. 프레스 기계가 너무 무거워서 손을 다칠 뻔했어요.","a":["기계가 고장 나서","손을 다칠 뻔해서","일을 다 끝내서","공구함이 없어서"],"c":"손을 다칠 뻔해서","ex":"Tuan hampir saja mengalami kecelakaan serius pada tangannya saat bekerja dengan mesin press (손을 다칠 뻔했어요).","romaji":"Tuan ssineun wae \"keunil nal ppeonhaetda\"go mal-haesseumnikka?","ch":48},{"id":"l_48_02","q":"남자는 여자에게 무엇을 주의하라고 했습니까?","audio":"리한 씨가 다쳐서 병원에 갔어요. 네, 그리고 용접기가 아직 뜨거우니까 미영 씨도 다치지 않도록 조심하세요.","a":["차가운 물","무거운 상자","뜨거운 용접기","미끄러운 바닥"],"c":"뜨거운 용접기","ex":"Tuan mengingatkan Miyeong agar berhati-hati terhadap mesin las yang masih panas (용접기가 아직 뜨거우니까).","romaji":"Namjaneun yeoja-ege mueoseul juui-harago haesseumnikka?","ch":48},{"id":"l_48_03","q":"이 사람은 이전에 이 작업을 해 본 적이 있습니까?","audio":"이 기계 써 본 적 있어요? 아니요, 한 번도 없어요. 어떻게 사용하는지 좀 가르쳐 주세요.","a":["네, 많이 해 봤습니다.","아니요, 한 번도 없습니다.","예전에 배운 적이 있습니다.","지금 하고 있는 중입니다."],"c":"아니요, 한 번도 없습니다.","ex":"Orang tersebut menyatakan belum pernah (한 번도 없어요) menggunakan mesin itu sebelumnya.","romaji":"I sarameun ijeone i jagyeobeul hae bon jeogi isseumnikka?","ch":48},{"id":"l_48_04","q":"소화기 사용 순서로 맞는 것을 고르십시오.","audio":"불이 나면 먼저 소화기를 가져오세요. 안전핀을 뽑고 호스를 불 쪽으로 향하게 하세요. 그 다음 손잡이를 강하게 움켜쥐고 불을 끄면 됩니다.","a":["안전핀 뽑기 - 호스 향하기 - 손잡이 쥐기","손잡이 쥐기 - 안전핀 뽑기 - 호스 향하기","호스 향하기 - 손잡이 쥐기 - 안전핀 뽑기","안전핀 뽑기 - 손잡이 쥐기 - 호스 향하기"],"c":"안전핀 뽑기 - 호스 향하기 - 손잡이 쥐기","ex":"Urutan penggunaan APAR adalah mencabut pin, mengarahkan selang, lalu menekan tuas.","romaji":"Sohwagi sayong sunseoro manneun geoseul goreusipsio.","ch":48},{"id":"l_48_05","q":"대화 내용으로 알 수 있는 사고의 원인은 무엇입니까?","audio":"여: 손가락이 기계에 끼었어요! 어서 기계를 끄세요! 남: 괜찮아요? 아유, 장갑을 끼고 밀링 작업을 하면 안 된다고 했잖아요. 장갑이 기계에 감겨서 사고가 난 거예요.","a":["기계가 너무 낡아서","장갑이 기계에 감겨서","바닥이 너무 미끄러워서","불꽃이 튀어서"],"c":"장갑이 기계에 감겨서","ex":"Kecelakaan terjadi karena sarung tangan terlilit ke dalam mesin milling (장갑이 기계에 감겨서).","romaji":"Daehwa naeyong-euro al su itneun sagoyi wonineun mueosimnikka?","ch":48},{"id":"l_49_01","q":"남자는 왜 지금 장갑을 껴야 합니까?","audio":"리한 씨, 기계가 뜨거우니까 안전장갑을 착용하세요. 네, 알겠습니다. 지금 얼른 낄게요.","a":["기계가 차가워서","기계가 뜨거워요","기계가 더러워서","기계가 고장 나서"],"c":"기계가 뜨거워요","ex":"Rihan harus memakai sarung tangan keselamatan karena mesinnya panas (기계가 뜨거우니까).","romaji":"Namjaneun wae jigeum janggabeul kkyeoya hamnikka?","ch":49},{"id":"l_49_02","q":"남자가 지금 바로 해야 할 일은 무엇입니까?","audio":"보안경을 안 쓰면 파편이 눈에 들어갈 수 있어요. 얼른 쓰고 오겠습니다.","a":["안전화 신기","보안경 쓰기","귀마개 하기","마스크 쓰기"],"c":"보안경 쓰기","ex":"Pria tersebut akan segera memakai kacamata pelindung (보안경) agar matanya tidak terkena serpihan.","romaji":"Namjaga jigeum baro haeya hal ireun mueosimnikka?","ch":49},{"id":"l_49_03","q":"발을 보호하기 위해 무엇을 신어야 합니까?","audio":"작업장에서 무거운 물건을 떨어뜨리면 발을 다칠 수 있어요. 그러니까 꼭 안전화를 신으세요.","a":["슬리퍼","운동화","안전화","장화"],"c":"안전화","ex":"Untuk melindungi kaki dari benda jatuh, harus memakai sepatu keselamatan (안전화).","romaji":"Bareul bohohagi wihae mueoseul sineoya hamnikka?","ch":49},{"id":"l_49_04","q":"남자가 해야 할 일이 아닌 것은 무엇입니까?","audio":"남: 시끄럽지만 귀마개를 하면 불편해서요. 여: 그래도 여긴 소음이 심하기 때문에 귀마개를 꼭 해야 돼요. 그리고 마스크도 쓰는 게 좋아요. 아! 작업이 끝난 후에는 기계의 플러그도 빼서 정리해 놓으세요.","a":["귀마개 하기","마스크 쓰기","플러그 빼기","창문 열기"],"c":"창문 열기","ex":"Wanita menyuruh memakai penutup telinga, masker, dan mencabut steker, tetapi tidak menyuruh membuka jendela.","romaji":"Namjaga haeya hal iri anin geoseun mueosimnikka?","ch":49},{"id":"l_49_05","q":"대화 내용과 일치하는 것을 고르십시오.","audio":"남: 반장님, 안전모가 너무 답답한데 좀 벗어도 될까요? 여: 안 돼요. 위에서 물건이 떨어질 수도 있기 때문에 안전모는 필수예요. 남: 네, 알겠습니다. 턱끈도 단단히 조일게요. 여: 그리고 안전화도 잘 챙겨 신으세요.","a":["남자는 안전모를 벗었습니다.","안전모는 물건이 떨어질 때 필요합니다.","남자는 안전화를 신지 않아도 됩니다.","턱끈은 느슨하게 하는 것이 좋습니다."],"c":"안전모는 물건이 떨어질 때 필요합니다.","ex":"Helm (안전모) wajib digunakan untuk melindungi dari benda yang mungkin jatuh dari atas.","romaji":"Daehwa naeyong-gwa ilchihaneun geoseul goreusipsio.","ch":49},{"id":"l_50_01","q":"모니카 씨는 왜 상을 받게 되었습니까?","audio":"모니카 씨, 우수 사원으로 뽑힌 거 축하해요. 일도 잘하고 작업장 점검도 꼼꼼히 잘한 덕분이에요.","a":["청소를 안 해서","일을 꼼꼼히 잘해서","병원에 가서","요리를 잘해서"],"c":"일을 꼼꼼히 잘해서","ex":"Monika terpilih sebagai pegawai terbaik karena bekerja dengan baik dan melakukan pengecekan tempat kerja dengan teliti (꼼꼼히 잘한 덕분).","romaji":"Monica ssineun wae sangeul batge doe-eot-seumnikka?","ch":50},{"id":"l_50_02","q":"남자는 이번 주말에 무엇을 하기로 했습니까?","audio":"리한 씨, 등산화를 샀네요? 네, 이번 주말에 회사 동료들이랑 같이 등산을 가기로 했어요.","a":["축구를 합니다","등산을 갑니다","영화를 봅니다","낮잠을 잡니다"],"c":"등산을 갑니다","ex":"Pria tersebut memutuskan untuk pergi naik gunung (등산을 가기로 했어요) akhir pekan ini.","romaji":"Namjaneun ibon jumare mueoseul hagiro haesseumnikka?","ch":50},{"id":"l_50_03","q":"남자는 왜 다치지 않았습니까?","audio":"투안 씨, 괜찮아요? 네, 다행히 미리 확인한 덕분에 다치지 않았어요. 점검이 정말 중요하네요.","a":["운이 좋아서","미리 확인한 덕분에","친구가 도와줘서","운동을 많이 해서"],"c":"미리 확인한 덕분에","ex":"Tuan tidak terluka berkat pengecekan yang dilakukan sebelumnya (미리 확인한 덕분에).","romaji":"Namjaneun wae dachiji anasseumnikka?","ch":50},{"id":"l_50_04","q":"남자에 대한 설명으로 맞는 것을 고르십시오.","audio":"여: 수진 씨, 병원에는 웬일이에요? 남: 저는 검진 결과를 보러 왔어요. 여: 그래요? 결과 잘 나왔어요? 남: 제가 운동을 너무 안 해서요. 유산소 운동도 하고 음식을 골고루 섭취하라고 했어요.","a":["남자는 지금 아주 건강합니다.","남자는 운동이 필요합니다.","남자는 병원에 처음 왔습니다.","남자는 음식을 가려 먹어야 합니다."],"c":"남자는 운동이 필요합니다.","ex":"Berdasarkan hasil pemeriksaan, pria tersebut kurang olahraga dan disarankan melakukan olahraga aerobik (유산소 운동... 하라고 했어요).","romaji":"Namja-e daehan seolmyeong-euro manneun geoseul goreusipsio.","ch":50},{"id":"l_50_05","q":"건강을 위해 해야 할 행동으로 알맞지 않은 것은 무엇입니까?","audio":"여러분, 건강을 유지하려면 틈틈이 스트레칭을 하는 것이 좋습니다. 그리고 음식을 골고루 섭취하고 표준 체중을 유지하도록 하세요. 밤에 자기 전에는 충분한 휴식을 취하는 것도 잊지 마세요.","a":["틈틈이 스트레칭 하기","음식을 골고루 먹기","휴식을 취하지 않기","표준 체중 유지하기"],"c":"휴식을 취하지 않기","ex":"Teks menyarankan untuk beristirahat cukup, sehingga \"tidak beristirahat\" adalah tindakan yang salah.","romaji":"Geongangeul wihae haeya hal haengdong-euro almaji anneun geoseun mueosimnikka?","ch":50},{"id":"l_51_01","q":"이반 씨는 어떤 일을 하고 싶어 합니까?","audio":"안녕하세요. 저는 한국에서 일하고 싶어서 왔습니다. 저는 가구를 만드는 제조업 쪽 일을 해 보고 싶어요.","a":["어업","농업","축산업","제조업"],"c":"제조업","ex":"Ivan secara spesifik menyebutkan ingin bekerja di bidang industri manufaktur (제조업).","romaji":"Ivan ssineun eotteon ireul hago sipeo hamnikka? / Annyeonghaseyo. Jeoneun Hangug-eseo ilhago sipeoseo wasseumnida. Jeoneun gagureul mandeuneun jejoeop jjok ireul hae bogo sipeoyo.","ch":51},{"id":"l_51_02","q":"고용허가제로 한국에 가면 처음 몇 년 동안 일할 수 있습니까?","audio":"고용허가제로 한국에 가면 처음 취업 기간은 3년입니다. 재계약을 하면 더 있을 수 있습니다.","a":["1년","2년","3년","5년"],"c":"3년","ex":"Masa kerja awal (취업 기간) di bawah sistem izin kerja (EPS) adalah 3 tahun.","romaji":"Goyong-heogajero Hanguge gamyeon cheoeum myeot nyeon dongan ilhal su itseumnikka?","ch":51},{"id":"l_51_03","q":"한국어능력시험은 각각 몇 문제씩 나옵니까?","audio":"한국어능력시험은 듣기하고 읽기만 나옵니다. 문제는 각각 25문제씩 나옵니다.","a":["10문제","20문제","25문제","50문제"],"c":"25문제","ex":"Masing-masing bagian (menyimak dan membaca) terdiri dari 25 soal.","romaji":"Hangugeoneungnyeoksieomeun gakgak myeot munjessik naomnikka?","ch":51},{"id":"l_51_04","q":"한국어능력시험 합격 기준에 대한 설명으로 맞는 것을 고르십시오.","audio":"한국어능력시험은 200점 만점 기준입니다. 80점이 넘은 사람 중에서 성적이 높은 사람부터 고용허가제로 일할 수 있는 자격이 주어지게 됩니다. 열심히 공부해서 높은 점수를 받으세요.","a":["100점이 만점입니다.","50점만 넘으면 합격입니다.","성적이 높은 사람부터 선발됩니다.","모든 사람이 자격을 얻습니다."],"c":"성적이 높은 사람부터 선발됩니다.","ex":"Dari orang yang mendapat nilai di atas 80 (dari total 200), mereka yang memiliki nilai tertinggilah yang akan dipilih terlebih dahulu.","romaji":"Hangugeoneungnyeoksieom hapgyeok gijune daehan seolmyeong-euro manneun geoseul goreusipsio.","ch":51},{"id":"l_51_05","q":"남자는 지금 무엇을 하고 있습니까?","audio":"가: 한국에 가서 일을 하고 싶은데요. 어떻게 신청해야 하죠? 나: 아, 그러세요? 먼저 고용허가제에 대해서 궁금한 것을 문의하고 신청서를 작성하시면 됩니다. 이쪽으로 앉으세요.","a":["서류를 제출하고 있습니다.","한국어를 공부하고 있습니다.","고용허가제에 대해 문의하고 있습니다.","비행기 표를 예매하고 있습니다."],"c":"고용허가제에 대해 문의하고 있습니다.","ex":"Pria tersebut datang untuk bertanya (문의하다) tentang cara mendaftar kerja ke Korea melalui sistem izin kerja.","romaji":"Namjaneun jigeum mueoseul hago itseumnikka?","ch":51},{"id":"l_52_01","q":"남자는 무엇에 대해 궁금해합니까?","audio":"여보세요. 안녕하세요. 고용허가제 근로 조건에 대해서 궁금한 게 있어서 전화드렸습니다. 근무 시간에 대해 알려주세요.","a":["보험 가입","근로 조건","이사 방법","한국 음식"],"c":"근로 조건","ex":"Pria tersebut menelepon karena ingin tahu mengenai syarat/kondisi kerja (근로 조건).","romaji":"Namjaneun mueose daehae gunggeum-haehamnikka?","ch":52},{"id":"l_52_02","q":"일이 많을 때는 어떤 근무를 할 수 있습니까?","audio":"보통은 계약서에 있는 근무 시간에만 일을 하면 됩니다. 하지만 일이 많을 때에는 연장 근무나 휴일 근무를 할 수도 있습니다.","a":["수습 근무","조기 퇴근","연장 근무","교육 참여"],"c":"연장 근무","ex":"Jika pekerjaan menumpuk, dimungkinkan adanya kerja lembur (연장 근무) atau kerja di hari libur.","romaji":"Iri maneul ttaeneun eotteon geunmureul hal su itseumnikka?","ch":52},{"id":"l_52_03","q":"이반 씨는 언제 근무지를 알 수 있습니까?","audio":"근무지는 아직 정해지지 않았습니다. 근무지는 한국에 입국한 후 취업 교육을 받은 후에 알려 준다고 합니다.","a":["입국 전","계약 시","취업 교육 후","3년 후"],"c":"취업 교육 후","ex":"Lokasi penempatan kerja akan diberitahukan setelah masuk ke Korea dan menyelesaikan pelatihan kerja (취업 교육).","romaji":"Ivan ssineun eonje geunmujireul al su itseumnikka?","ch":52},{"id":"l_52_04","q":"대화 내용과 일치하는 것을 고르십시오.","audio":"가: 계약서를 잘 확인해 봤어요? 나: 네, 업무 내용이랑 임금 모두 마음에 들어요. 근로 조건이 좋은 것 같아요. 가: 다행이네요. 그럼 여기 서명란에 사인하세요. 나: 네, 알겠습니다.","a":["임금이 마음에 들지 않습니다.","남자는 계약서에 서명을 했습니다.","여자는 일을 그만두려고 합니다.","업무 내용이 아직 정해지지 않았습니다."],"c":"남자는 계약서에 서명을 했습니다.","ex":"Karena pria tersebut menyukai kondisi kerjanya, ia diminta untuk tanda tangan (사인하세요/서명) di kolom tanda tangan.","romaji":"Daehwa naeyong-gwa ilchihaneun geoseul goreusipsio.","ch":52},{"id":"l_52_05","q":"여자는 무엇 때문에 걱정하고 있습니까?","audio":"가: 지수 씨, 얼굴이 안 좋네요. 무슨 일 있어요? 나: 근로 계약서를 다시 확인하고 싶은데 아무리 찾아도 없어요. 잃어버린 것 같아요. 가: 아, 그래요? 사장님께 말씀드리고 사본을 한 장 더 받을 수 있는지 물어보세요.","a":["월급이 적어서","기숙사가 멀어서","계약서를 잃어버려서","일이 너무 힘들어서"],"c":"계약서를 잃어버려서","ex":"Wanita tersebut khawatir karena tidak bisa menemukan kontrak kerjanya dan menduga kontrak tersebut hilang (잃어버리다).","romaji":"Yeojaneun mueot ttaemune geokjeong-hago itseumnikka?","ch":52},{"id":"l_53_01","q":"외국인 등록을 하려면 어디에 가야 합니까?","audio":"한국에 온 지 일주일이 됐네요. 이제 외국인 등록을 하러 출입국관리사무소에 가야 합니다.","a":["대사관","은행","경찰서","출입국관리사무소"],"c":"출입국관리사무소","ex":"Untuk mendaftarkan status kependudukan (alien registration), seseorang harus pergi ke kantor imigrasi (출입국관리사무소).","romaji":"Oegugin deungnogeul haryeomeun eodie gaya hamnikka?","ch":53},{"id":"l_53_02","q":"입국 심사를 받을 때 무엇을 해야 합니까?","audio":"여기에 손가락을 대 주시고요, 이쪽에 있는 카메라를 보세요. 심사가 끝날 때까지 잠시만 기다려 주세요.","a":["춤을 춥니다","노래를 합니다","지문을 찍고 사진을 찍습니다","가방을 엽니다"],"c":"지문을 찍고 사진을 찍습니다","ex":"Saat pemeriksaan imigrasi, pendatang diminta menempelkan jari (untuk sidik jari) dan melihat ke kamera (untuk foto wajah).","romaji":"Ipguk simsareul badeul ttae mueoseul haeya hamnikka?","ch":53},{"id":"l_53_03","q":"여자는 지금 무엇을 하고 있습니까?","audio":"가: 수미 씨, 지금 뭐 해요? 나: 입국 심사를 받고 있어요. 가: 그래요? 그럼 다 끝나고 전화해 주세요.","a":["서류를 제출하고 있습니다.","입국 심사를 받고 있습니다.","취업 교육을 받고 있습니다.","외국인 등록을 하고 있습니다."],"c":"입국 심사를 받고 있습니다.","ex":"Su-mi menjawab bahwa dia sedang menjalani pemeriksaan imigrasi (입국 심사).","romaji":"Yeojaneun jigeum mueoseul hago itseumnikka?","ch":53},{"id":"l_53_04","q":"외국인 등록 신청 시 필요한 서류가 아닌 것은 무엇입니까?","audio":"외국인 등록을 하러 오셨나요? 그럼 신청서하고 여권, 증명사진 3장이 필요합니다. 그리고 사업자 등록증 사본도 주셔야 합니다.","a":["여권","증명사진","신청서","고향 집 주소"],"c":"고향 집 주소","ex":"Dokumen yang diperlukan adalah formulir, paspor, foto, dan salinan izin usaha. Alamat rumah di kampung halaman tidak disebutkan sebagai syarat.","romaji":"Oegugin deungnok sincheong si piryohan seoryuga anin geoseun mueosimnikka?","ch":53},{"id":"l_53_05","q":"취업 교육에 대한 설명으로 맞는 것을 고르십시오.","audio":"고용허가제로 입국한 외국인 근로자는 사업장에 배치되기 전에 반드시 취업 교육을 받아야 합니다. 보통 2박 3일 동안 16시간의 교육을 받게 됩니다. 이 교육은 한국 생활 적응에 큰 도움이 됩니다.","a":["교육은 1시간만 받습니다.","일한 후에 교육을 받습니다.","16시간 동안 교육을 받습니다.","모든 교육은 인터넷으로 합니다."],"c":"16시간 동안 교육을 받습니다.","ex":"Pelatihan kerja dilakukan selama 16 jam (biasanya 3 hari 2 malam) sebelum ditempatkan di tempat kerja.","romaji":"Chwieop gyoyuge daehan seolmyeong-euro manneun geoseul goreusipsio.","ch":53},{"id":"l_54_01","q":"외국인 근로자가 반드시 가입해야 하는 보험은 무엇입니까?","audio":"고용허가제를 통해 한국에 온 외국인 근로자는 반드시 상해 보험에 가입해야 합니다. 산재 보험과는 다릅니다.","a":["자동차 보험","화재 보험","상해 보험","여행 보험"],"c":"상해 보험","ex":"Pekerja asing di bawah sistem EPS wajib mendaftar asuransi kecelakaan (상해 보험).","romaji":"Oegugin geunrojaga bandeusi gaipaeya haneun boeomeun mueosimnikka?","ch":54},{"id":"l_54_02","q":"보험금을 청구하려면 무엇을 제출해야 합니까?","audio":"보험금을 청구하고 싶은데요. 어떻게 해야 하죠? 먼저 신청서를 쓰시고, 병원에서 진단서를 받아 오시면 됩니다.","a":["여권만 제출합니다","진단서와 신청서를 제출합니다","돈을 냅니다","사진만 찍습니다"],"c":"진단서와 신청서를 제출합니다","ex":"Untuk klaim asuransi, diperlukan formulir aplikasi dan surat keterangan dokter/rekam medis (진단서).","romaji":"Boeomgeumeul cheong-guharyeomeun mueoseul jechul-haeya hamnikka?","ch":54},{"id":"l_54_03","q":"산재 보험은 언제 보상을 받을 수 있습니까?","audio":"산재 보험은 업무상 재해 시에만 받을 수 있습니다. 작업장에서 일하다가 다쳤을 때 신청하세요.","a":["여행 중 다쳤을 때","집에서 아플 때","업무상 재해 시에만","친구와 싸웠을 때"],"c":"업무상 재해 시에만","ex":"Asuransi kecelakaan kerja (산재 보험) hanya memberikan kompensasi jika terjadi kecelakaan saat bekerja (업무상 재해).","romaji":"Sanjae boeomeun eonje bosangeul badeul su itseumnikka?","ch":54},{"id":"l_54_04","q":"대화 내용으로 알 수 있는 것은 무엇입니까?","audio":"남: 보험금을 청구할 때 어떤 치료를 받았는지 볼 수 있는 서류가 필요하다고 해요. 나: 아, 그 서류는 병원에서 발급받을 수 있어요. 진단서나 내역서를 준비해 보세요. 남: 고마워요. 내일 병원에 다녀올게요.","a":["남자는 지금 병원에 있습니다.","남자는 보험금을 이미 받았습니다.","필요한 서류는 병원에서 받을 수 있습니다.","서류는 회사에서 준비해 줍니다."],"c":"필요한 서류는 병원에서 받을 수 있습니다.","ex":"Dokumen yang menunjukkan jenis perawatan yang diterima (seperti 진단서) dapat diperoleh dari rumah sakit.","romaji":"Daehwa naeyong-euro al su itneun geoseun mueosimnikka?","ch":54},{"id":"l_54_05","q":"남자가 평균 임금의 70%를 받을 수 있는 이유는 무엇입니까?","audio":"여: 다쳐서 일도 못 하고 생활이 어려워서 어떡해요. 남: 그래도 다행이에요. 산재 보험 덕분에 일을 못 하는 동안 평균 임금의 70%를 휴업 급여로 받을 수 있거든요. 여: 정말 다행이네요.","a":["상여금을 받아서","휴업 급여를 받을 수 있어서","월급이 올라서","친구가 돈을 빌려줘서"],"c":"휴업 급여를 받을 수 있어서","ex":"Pria tersebut bisa mendapatkan 70% dari upah rata-ratanya sebagai tunjangan cuti sakit/tidak bekerja (휴업 급여) melalui asuransi.","romaji":"Namjaga pyeonggyun imgeumui chilssipposenteureul badeul su itneun iyuneun mueosimnikka?","ch":54},{"id":"l_55_01","q":"이반 씨가 실제로 받는 돈을 무엇이라고 합니까?","audio":"이반 씨, 급여 명세서를 보세요. 여기 실수령액이라고 있죠? 이게 이반 씨가 실제로 받는 돈이에요.","a":["기본급","총액","실수령액","식대"],"c":"실수령액","ex":"Jumlah uang yang benar-benar diterima oleh pekerja setelah dikurangi pajak dan asuransi disebut \"sil-suryeong-aek\" (실수령액).","romaji":"Ivan ssiga siljero batneun doneul mueosirago hamnikka?","ch":55},{"id":"l_55_02","q":"이번 달에 월급이 왜 생각보다 적습니까?","audio":"월급이 계약서보다 적은 것 같아요. 그건 각종 보험료와 세금을 공제했기 때문이에요. 세금을 뺀 만큼 받게 됩니다.","a":["일을 안 해서","세금과 보험료를 빼서","사장님이 돈이 없어서","은행이 문을 닫아서"],"c":"세금과 보험료를 빼서","ex":"Gaji terasa lebih sedikit karena adanya pemotongan (공제) untuk pajak dan asuransi.","romaji":"Ibeon dare wolgeubi wae saenggakboda jeokseumnikka?","ch":55},{"id":"l_55_03","q":"보너스는 보통 무엇을 기준으로 계산합니까?","audio":"가: 보너스는 어떻게 계산해요? 나: 보통은 기본급을 기준으로 100%, 200% 이렇게 계산해서 지급해요.","a":["시급","기본급","세금","식비"],"c":"기본급","ex":"Bonus (상여금) biasanya dihitung berdasarkan standar gaji pokok (기본급).","romaji":"Boneoseuneun botong mueoseul gijuneuro gyesan-hamnikka?","ch":55},{"id":"l_55_04","q":"여자가 이번 달에 월급을 많이 받은 이유는 무엇입니까?","audio":"여: 이번 달은 월급이 평소보다 많네요. 남: 그래요? 연장 근무랑 야간 근무를 많이 했나 봐요? 여: 네, 일이 많아서 밤늦게까지 일을 자주 했거든요. 수당이 많이 포함된 것 같아요.","a":["기본급이 올라서","일을 적게 해서","연장 및 야간 근무 수당 때문에","세금을 안 내서"],"c":"연장 및 야간 근무 수당 때문에","ex":"Gaji menjadi lebih banyak karena adanya tambahan upah lembur dan kerja malam (수당/연장/야간 근무).","romaji":"Yeojaga ibeon dare wolgeubeul mani badeun iyuneun mueosimnikka?","ch":55},{"id":"l_55_05","q":"법정 근로 시간에 대한 설명으로 알맞지 않은 것은 무엇입니까?","audio":"법으로 정해진 근로 시간을 법정 근로 시간이라고 합니다. 근로 시간은 1주일에 40시간을 넘을 수 없고 1일에 8시간을 넘으면 안 됩니다. 만약 이 시간을 넘겨서 일하면 수당을 더 받아야 합니다.","a":["1일 8시간이 기준입니다.","1주일 40시간이 기준입니다.","시간을 넘기면 돈을 더 받습니다.","주말에는 무조건 쉬어야 합니다."],"c":"주말에는 무조건 쉬어야 합니다.","ex":"Teks menyebutkan standar 8 jam sehari dan 40 jam seminggu, serta upah lembur jika melebihi itu. Larangan bekerja di akhir pekan secara mutlak tidak disebutkan.","romaji":"Beopjeong geunro sigane daehan seolmyeong-euro almaji anneun geoseun mueosimnikka?","ch":55}];if(!window.Bank._listeningLoaded){["beginner","normal","pro"].forEach(function(lvl){if(window.Bank&&window.Bank[lvl]){if(!window.Bank[lvl].listening)window.Bank[lvl].listening=[];window.Bank[lvl].listening=window.Bank[lvl].listening.concat(items);}});window.Bank._listeningLoaded=true;}})();